// Unit 35: Prüfung B2
// Level: B2

const UNIT_35 =
{n:35,lang:"de",srcLang:"en",track:"v2",title:"Prüfung B2",sub:"Die letzte Hürde",icon:"📝",level:"B2.2",color:"#7B5EE8",lessons:[
{id:"deu_r35l1",title:"Pr\u00fcfungstag",icon:"\ud83d\udcdd",xp:15,board:true,steps:[
{type:"intro",title:"Pr\u00fcfungstag",desc:"Verumius stands in front of the Goethe-Institut. Today is the B2 exam day. Same door as the B1 exam, but the expectations are higher.",goals:["Learn 17 words related to the exam","Understand the four sections of the Goethe B2","Express nervousness and determination","Know exam strategies in German"]},
{type:"teach",trg:"der Pr\u00fcfungsteil",src:"exam section",pos:"noun",gender:"m",note:"Pr\u00fcfung (exam) + Teil (part). An exam section.\nDer Goethe B2 hat vier Pr\u00fcfungsteile.",example:"A: Wie viele Pr\u00fcfungsteile hat die B2-Pr\u00fcfung?\nB: Vier Pr\u00fcfungsteile.\nA: Welcher Pr\u00fcfungsteil ist am schwersten?\nB: F\u00fcr mich das H\u00f6rverstehen.",exampleSrc:"A: How many exam sections does the B2 exam have?\nB: Four exam sections.\nA: Which exam section is the hardest?\nB: For me, the listening comprehension.",funFact:"Pr\u00fcfung (exam) + Teil (part). The Goethe B2 has four Pr\u00fcfungsteile: Lesen, H\u00f6ren, Schreiben, Sprechen. Masculine because Teil is masculine. Each Teil has its own time limit."},
{type:"teach",trg:"das H\u00f6rverstehen",src:"listening comprehension",pos:"noun",gender:"n",note:"H\u00f6ren (to hear) + Verstehen (understanding).\nTests understanding of spoken German at natural speed.",example:"A: Das H\u00f6rverstehen war schwer.\nB: Ja, die Sprecher waren sehr schnell.\nA: Wie \u00fcbt man H\u00f6rverstehen?\nB: Mit Podcasts und Radio.",exampleSrc:"A: The listening comprehension was hard.\nB: Yes, the speakers were very fast.\nA: How do you practice listening comprehension?\nB: With podcasts and radio.",funFact:"H\u00f6ren (to hear) + Verstehen (understanding). Das H\u00f6rverstehen tests whether you can understand spoken German at natural speed. Radio interviews, announcements, conversations. Neuter because Verstehen is neuter."},
{type:"teach",trg:"das Leseverstehen",src:"reading comprehension",pos:"noun",gender:"n",note:"Lesen (to read) + Verstehen (understanding).\nRequires understanding newspaper articles and formal texts.",example:"A: Leseverstehen dauert 65 Minuten.\nB: Das ist viel Text.\nA: Was kommt im Leseverstehen vor?\nB: Zeitungsartikel und formelle Briefe.",exampleSrc:"A: Reading comprehension takes 65 minutes.\nB: That is a lot of text.\nA: What comes in the reading comprehension?\nB: Newspaper articles and formal letters.",funFact:"Lesen (to read) + Verstehen (understanding). Das Leseverstehen requires understanding newspaper articles, formal letters, and academic texts at B2 level. The hardest section for many candidates."},
{type:"teach",trg:"die Schreibaufgabe",src:"writing task",pos:"noun",gender:"f",note:"Schreiben (to write) + Aufgabe (task).\nAt B2: a structured essay with 250+ words in 75 minutes.",example:"A: Die Schreibaufgabe war interessant.\nB: Was war das Thema?\nA: Digitale Medien in der Schule.\nB: Oh, dar\u00fcber kann man viel schreiben.",exampleSrc:"A: The writing task was interesting.\nB: What was the topic?\nA: Digital media in school.\nB: Oh, you can write a lot about that.",funFact:"Schreiben (to write) + Aufgabe (task). Die Schreibaufgabe at B2 level asks you to write a structured essay with introduction, arguments, and conclusion. 250+ words in 75 minutes."},
{type:"teach",trg:"der Sprachbaustein",src:"language building block",pos:"noun",gender:"m",note:"Sprache (language) + Baustein (building block).\nTests grammar and vocabulary in context.",example:"A: Was sind Sprachbausteine?\nB: L\u00fccken im Text, die man f\u00fcllen muss.\nA: Also ein Grammatiktest?\nB: Ja, aber im Kontext, nicht isoliert.",exampleSrc:"A: What are language building blocks?\nB: Gaps in the text that you must fill.\nA: So a grammar test?\nB: Yes, but in context, not in isolation.",funFact:"Sprache (language) + Baustein (building block). The Sprachbausteine section tests grammar and vocabulary in context: fill-in-the-blank with connectors, prepositions, and verb forms. Masculine because Baustein is masculine."},
{type:"fb",s:"Die Goethe-Pr\u00fcfung hat vier {1}: Lesen, H\u00f6ren, Schreiben und Sprechen.",a:["Pr\u00fcfungsteile"],opts:["Pr\u00fcfungsteile","Schreibaufgaben","Sprachbausteine","Leseverstehen"],hint:"The compound noun for exam sections. Pr\u00fcfung + Teil (part). Each one tests a different skill.",sSrc:"The Goethe exam has four exam sections: reading, listening, writing, and speaking."},
{type:"teach",trg:"die Textproduktion",src:"text production",pos:"noun",gender:"f",note:"Text + Produktion (production). The formal term for writing\nan essay. At B2: argumentation, not just description.",example:"A: Textproduktion ist der schwierigste Teil.\nB: Warum?\nA: Man muss argumentieren, nicht nur beschreiben.\nB: Struktur und Ausdruck z\u00e4hlen.",exampleSrc:"A: Text production is the hardest part.\nB: Why?\nA: You have to argue, not just describe.\nB: Structure and expression count.",funFact:"Text + Produktion (production). Die Textproduktion. The formal term for writing an essay. At B2 level, Textproduktion means argumentation, not just description. Always feminine because of the -tion ending."},
{type:"teach",trg:"die Pr\u00fcfungsvorbereitung",src:"exam preparation",pos:"noun",gender:"f",note:"Pr\u00fcfung + Vorbereitung (preparation).\nEvery Goethe-Institut offers special courses for this.",example:"A: Hast du eine Pr\u00fcfungsvorbereitung gemacht?\nB: Ja, einen Intensivkurs.\nA: Hat die Pr\u00fcfungsvorbereitung geholfen?\nB: Sehr. Ich kenne jetzt alle Aufgabentypen.",exampleSrc:"A: Did you do an exam preparation course?\nB: Yes, an intensive course.\nA: Did the exam preparation help?\nB: A lot. I now know all the task types.",funFact:"Pr\u00fcfung + Vorbereitung (preparation). Every Goethe-Institut offers Pr\u00fcfungsvorbereitung courses. The compound is long but each part is familiar. Vorbereitung from 'vor' (before) + 'bereiten' (to prepare)."},
{type:"teach",trg:"die Pr\u00fcfungsangst",src:"exam anxiety",pos:"noun",gender:"f",note:"Pr\u00fcfung + Angst (fear/anxiety). A recognized psychological\ncondition. Even native speakers experience it.",example:"A: Hast du Pr\u00fcfungsangst?\nB: Ja, jedes Mal.\nA: Was hilft gegen Pr\u00fcfungsangst?\nB: Tief atmen und gut vorbereitet sein.",exampleSrc:"A: Do you have exam anxiety?\nB: Yes, every time.\nA: What helps against exam anxiety?\nB: Breathing deeply and being well prepared.",funFact:"Pr\u00fcfung + Angst (fear/anxiety). A real psychological condition recognized in Germany. Even native speakers experience Pr\u00fcfungsangst. The word 'Angst' entered English directly from German."},
{type:"teach",trg:"die Bearbeitungszeit",src:"time allowed, processing time",pos:"noun",gender:"f",note:"Bearbeitung (processing) + Zeit (time).\nEvery exam section has its Bearbeitungszeit printed at the top.",example:"A: Wie lang ist die Bearbeitungszeit?\nB: 75 Minuten f\u00fcr das Schreiben.\nA: Reicht die Bearbeitungszeit?\nB: Knapp. Man muss schnell arbeiten.",exampleSrc:"A: How long is the time allowed?\nB: 75 minutes for the writing section.\nA: Is the time allowed enough?\nB: Barely. You have to work fast.",funFact:"Bearbeitung (processing) + Zeit (time). Every exam section has its Bearbeitungszeit printed at the top. Managing it is half the battle. Feminine because Zeit is feminine."},
{type:"teach",trg:"bestehen",src:"to pass (an exam)",pos:"verb",gender:null,note:"Be- + stehen (to stand). Literally 'to stand through.'\nStrong verb: bestehen/bestand/bestanden.",example:"A: Hast du die Pr\u00fcfung bestanden?\nB: Ja, mit 78 Punkten!\nA: Herzlichen Gl\u00fcckwunsch!\nB: Danke. 'Bestanden!' ist das sch\u00f6nste Wort.",exampleSrc:"A: Did you pass the exam?\nB: Yes, with 78 points!\nA: Congratulations!\nB: Thanks. 'Passed!' is the most beautiful word.",funFact:"Be- + stehen (to stand). Literally 'to stand through.' You stand firm against the test. Strong verb: bestehen/bestand/bestanden. 'Bestanden!' is the best word on an exam certificate."},
{type:"mc",q:"Welches Wort beschreibt die Angst vor einer Pr\u00fcfung?",opts:["Pr\u00fcfungsvorbereitung","Bearbeitungszeit","Pr\u00fcfungsangst","Textproduktion"],ans:"Pr\u00fcfungsangst",hint:"A compound noun combining the word for exam with the word for fear. Even native speakers experience this feeling."}
]},
{id:"deu_r35l1b",title:"Pr\u00fcfungstag (Teil 2)",icon:"\ud83d\udcdd",xp:15,board:true,steps:[
{type:"intro",title:"Pr\u00fcfungstag (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"durchlesen",src:"to read through completely",pos:"verb",gender:null,note:"Durch (through) + lesen (to read). Separable.\nThe essential exam strategy: read everything first.",example:"A: Lies die Aufgabe zuerst ganz durch.\nB: Alles durchlesen, dann antworten?\nA: Genau. Durchlesen spart Zeit.\nB: Okay, ich lese alles durch.",exampleSrc:"A: Read the task through completely first.\nB: Read everything through, then answer?\nA: Exactly. Reading through saves time.\nB: Okay, I'll read everything through.",funFact:"Durch (through) + lesen (to read). Separable. The exam strategy: durchlesen before answering. Read ALL of it first. 'Lies die Aufgabe zuerst ganz durch.'"},
{type:"teach",trg:"markieren",src:"to mark, to highlight",pos:"verb",gender:null,note:"From French 'marquer.' The essential exam skill.\nMark first, answer second.",example:"A: Markier die Schl\u00fcsselw\u00f6rter.\nB: Mit Textmarker?\nA: Ja, markieren hilft beim Verstehen.\nB: Ich markiere immer die wichtigsten Stellen.",exampleSrc:"A: Mark the keywords.\nB: With a highlighter?\nA: Yes, marking helps with understanding.\nB: I always mark the most important parts.",funFact:"'Schluesselwoerter markieren' (mark keywords) is the essential exam skill. Mark first, answer second. Every Pruefungsvorbereitung teaches this. The verb came from French 'marquer.'"},
{type:"teach",trg:"korrigieren",src:"to correct, to proofread",pos:"verb",gender:null,note:"From Latin 'corrigere.' Five minutes at the end saves\nstupid mistakes. Always korrigieren before submission.",example:"A: Hast du den Text korrigiert?\nB: Ja, ich habe drei Fehler gefunden.\nA: Korrigieren ist wichtig.\nB: F\u00fcnf Minuten am Ende reichen.",exampleSrc:"A: Did you correct the text?\nB: Yes, I found three mistakes.\nA: Correcting is important.\nB: Five minutes at the end are enough.",funFact:"Korrekturlesen (proofreading) is the final exam step. Five minutes at the end saves careless mistakes. Always 'den Text korrigieren' before submission. Latin root: 'corrigere' (to set right)."},
{type:"teach",trg:"strukturieren",src:"to structure",pos:"verb",gender:null,note:"From Latin 'structura.' Einleitung, Hauptteil, Schluss.\nGerman examiners reward clear Struktur.",example:"A: Wie strukturierst du deinen Aufsatz?\nB: Einleitung, Hauptteil, Schluss.\nA: Gut strukturierte Texte bekommen bessere Noten.\nB: Ja, Struktur ist die halbe Miete.",exampleSrc:"A: How do you structure your essay?\nB: Introduction, main body, conclusion.\nA: Well-structured texts get better grades.\nB: Yes, structure is half the battle.",funFact:"German examiners reward clear Struktur above all. 'Den Aufsatz strukturieren' means organizing it into Einleitung, Hauptteil, Schluss (introduction, body, conclusion). Latin root: 'structura.'"},
{type:"teach",trg:"fortgeschritten",src:"advanced",pos:"adj",gender:null,note:"Fort (forward) + geschritten (stepped). B2 is the\nfortgeschritten level. Past participle used as adjective.",example:"A: Bist du Anf\u00e4nger?\nB: Nein, fortgeschritten.\nA: Fortgeschrittene Deutschkenntnisse?\nB: Ja, B2-Niveau.",exampleSrc:"A: Are you a beginner?\nB: No, advanced.\nA: Advanced German skills?\nB: Yes, B2 level.",funFact:"Fort (forward/onward) + geschritten (stepped). B2 is the fortgeschritten level. You have stepped forward from the basics. Past participle of 'fortschreiten' used as adjective."},
{type:"fb",s:"Die {1} f\u00fcr das Schreiben betr\u00e4gt 75 Minuten.",a:["Bearbeitungszeit"],opts:["Bearbeitungszeit","Pr\u00fcfungsangst","Pr\u00fcfungsvorbereitung","Schreibaufgabe"],hint:"The compound noun for the time allocated to complete a section. Bearbeitung (processing) + Zeit (time).",sSrc:"The time allowed for writing is 75 minutes."},
{type:"mc",q:"Was hilft gegen Pr\u00fcfungsangst?",opts:["Nichts, man muss einfach Angst haben","Tief atmen und gut vorbereitet sein","Die Pr\u00fcfung nicht ernst nehmen","Keine Pr\u00fcfungsvorbereitung machen"],ans:"Tief atmen und gut vorbereitet sein",hint:"Two strategies: one physical (breathing), one practical (preparation). Together they reduce the anxiety that comes before every exam."},
{type:"teach",trg:"pr\u00fcfungsrelevant",src:"exam-relevant",pos:"adj",gender:null,note:"Pr\u00fcfung + relevant. 'Ist das pr\u00fcfungsrelevant?' is the\nuniversal student question across all countries.",example:"A: Ist das pr\u00fcfungsrelevant?\nB: Ja, das kommt in der Pr\u00fcfung vor.\nA: Dann lerne ich das genauer.\nB: Alles hier ist pr\u00fcfungsrelevant.",exampleSrc:"A: Is that exam-relevant?\nB: Yes, that comes up in the exam.\nA: Then I'll study that more carefully.\nB: Everything here is exam-relevant.",funFact:"Pr\u00fcfung + relevant. 'Ist das pr\u00fcfungsrelevant?' is the universal student question. If it is on the exam, it is pr\u00fcfungsrelevant. If not, why study it?"},
{type:"teach",trg:"rechtzeitig",src:"on time, in good time",pos:"adv",gender:null,note:"Recht (right/proper) + zeitig (timely). Not just p\u00fcnktlich\n(punctual), but with a safety margin.",example:"A: Bist du rechtzeitig angekommen?\nB: Ja, 20 Minuten vor der Pr\u00fcfung.\nA: Gut. Rechtzeitig sein reduziert Stress.\nB: Lieber zu fr\u00fch als zu sp\u00e4t.",exampleSrc:"A: Did you arrive on time?\nB: Yes, 20 minutes before the exam.\nA: Good. Being on time reduces stress.\nB: Better too early than too late.",funFact:"Recht (right/proper) + zeitig (timely). Not 'p\u00fcnktlich' (punctual), but 'in proper time' with a margin. Germans arrive rechtzeitig, not just p\u00fcnktlich. The safety buffer is built into the word."},
{type:"mc",q:"Die Goethe-Pr\u00fcfung hat vier Pr\u00fcfungsteile. Welcher geh\u00f6rt NICHT dazu?",opts:["Lesen (reading section)","Schreiben (writing section)","H\u00f6ren (listening section)","\u00dcbersetzen (translating)"],ans:"\u00dcbersetzen (translating)",hint:"The four sections are Lesen, H\u00f6ren, Schreiben, and Sprechen. Translation is not tested.",sSrc:"The Goethe exam has four exam sections. Which does NOT belong?"},
{type:"fb",s:"Lies die Aufgabe zuerst komplett {1}.",a:["durch"],opts:["durch","vor","ab","an"],hint:"The separable prefix that signals reading something all the way to the end. Think of a directional prefix meaning movement through something completely.",sSrc:"Read the task through completely first."},
{type:"match",pairs:[{trg:"H\u00f6rverstehen",src:"listening comprehension"},{trg:"Leseverstehen",src:"reading comprehension"},{trg:"Bearbeitungszeit",src:"time allowed"},{trg:"Pr\u00fcfungsangst",src:"exam anxiety"},{trg:"bestehen",src:"to pass (an exam)"}]},
{type:"mc",q:"Was bedeutet 'strukturieren'?",opts:["exam section","to structure","reading comprehension","listening comprehension"],ans:"to structure",hint:"Sounds like its English equivalent. The -ieren suffix marks it as a loan verb."},
{type:"fb",s:"Bist du {1} angekommen?",a:["rechtzeitig"],opts:["durchlesen","die Schreibaufgabe","das Leseverstehen","rechtzeitig"],hint:"recht (right/proper) + zeitig (timely). Arriving at the right time, not late.",sSrc:"Did you arrive on time?"},
{type:"mc",q:"Dieser Grammatikpunkt ist {blank} und kommt haeufig in der Prüfung vor.",opts:["prüfungsrelevant","rechtzeitig","fehlerhaft","grammatikalisch"],ans:"prüfungsrelevant",hint:"Prüfung (exam) + relevant. Something that is likely to appear on the test and worth studying."}
]},
{id:"deu_r35l2",title:"Wortfeld Pr\u00fcfung",icon:"\ud83d\udcd6",xp:15,board:true,steps:[
{type:"intro",title:"Wortfeld Pr\u00fcfung",desc:"The vocabulary of the exam world. Task types, assessment criteria, and instructions you find on every exam sheet.",goals:["Learn 17 words about exams and assessment","Understand different task formats","Know what examiners look for"]},
{type:"teach",trg:"die Aufgabenstellung",src:"task prompt, question as formulated",pos:"noun",gender:"f",note:"Aufgabe (task) + Stellung (positioning).\nMisreading the Aufgabenstellung costs more points than wrong answers.",example:"A: Lies die Aufgabenstellung genau.\nB: Was steht in der Aufgabenstellung?\nA: 'Nehmen Sie Stellung zum Thema.'\nB: Also eine Meinung schreiben.",exampleSrc:"A: Read the task prompt carefully.\nB: What does the task prompt say?\nA: 'Take a position on the topic.'\nB: So write an opinion.",funFact:"Aufgabe (task) + Stellung (positioning). The task prompt. Reading the Aufgabenstellung carefully is the first rule of exams. Misreading it costs more points than wrong answers."},
{type:"teach",trg:"die Bewertung",src:"assessment, grade, evaluation",pos:"noun",gender:"f",note:"From bewerten (to evaluate) + -ung.\nAt B2: content, structure, grammar, and vocabulary range.",example:"A: Wie ist die Bewertung aufgebaut?\nB: Vier Kriterien: Inhalt, Aufbau, Grammatik, Wortschatz.\nA: Z\u00e4hlen alle Kriterien gleich?\nB: Ja, jedes Kriterium z\u00e4hlt gleich viel.",exampleSrc:"A: How is the assessment structured?\nB: Four criteria: content, structure, grammar, vocabulary.\nA: Do all criteria count equally?\nB: Yes, each criterion counts equally.",funFact:"At B2 level, Bewertung considers four criteria equally: content, structure, grammar, and vocabulary range. The noun comes from bewerten (to evaluate) + the -ung suffix."},
{type:"teach",trg:"das Kriterium",src:"criterion",pos:"noun",gender:"n",note:"From Greek 'kriterion' (standard of judgment).\nPlural: Kriterien. Same word across European languages.",example:"A: Nach welchen Kriterien wird bewertet?\nB: Inhalt, Struktur, Grammatik, Wortschatz.\nA: Ist jedes Kriterium gleich wichtig?\nB: Ja, alle vier Kriterien z\u00e4hlen.",exampleSrc:"A: By which criteria is it graded?\nB: Content, structure, grammar, vocabulary.\nA: Is each criterion equally important?\nB: Yes, all four criteria count.",funFact:"Das Kriterium, plural: Kriterien. 'Nach welchen Kriterien wird bewertet?' The word is nearly identical across European languages, going back to Greek 'kriterion' (standard of judgment)."},
{type:"teach",trg:"der Ma\u00dfstab",src:"standard, yardstick, scale",pos:"noun",gender:"m",note:"Ma\u00df (measure) + Stab (rod/staff). Literally a measuring rod.\nAlso means the scale on a map.",example:"A: Welchen Ma\u00dfstab legen die Pr\u00fcfer an?\nB: Einen hohen Ma\u00dfstab.\nA: Ist der Ma\u00dfstab bei B2 strenger?\nB: Ja, strenger als bei B1.",exampleSrc:"A: What standard do the examiners apply?\nB: A high standard.\nA: Is the standard stricter at B2?\nB: Yes, stricter than at B1.",funFact:"Ma\u00df (measure) + Stab (rod/staff). 'Einen hohen Ma\u00dfstab anlegen' (to apply a high standard). Literally a measuring rod. Also means the scale on a map. Context decides."},
{type:"mc",q:"Nach welchen Kriterien wird die Schreibaufgabe auf fortgeschrittenem Niveau bewertet?",opts:["Nur Grammatik und Rechtschreibung allein","Nur der Wortschatz und die L\u00e4nge des Textes","Inhalt, Textaufbau, Grammatik und Wortschatz","Handschrift, Schnelligkeit und Kreativit\u00e4t"],ans:"Inhalt, Textaufbau, Grammatik und Wortschatz",hint:"Four criteria, each counting equally. Content, structure, grammar, and vocabulary range determine the grade."},
{type:"teach",trg:"die Musterantwort",src:"model answer",pos:"noun",gender:"f",note:"Muster (sample/pattern) + Antwort (answer).\nGoethe-Institut publishes Musterantworten for every exam level.",example:"A: Gibt es eine Musterantwort?\nB: Ja, auf der Goethe-Website.\nA: Hilft die Musterantwort beim Lernen?\nB: Sehr. Sie zeigt die perfekte L\u00f6sung.",exampleSrc:"A: Is there a model answer?\nB: Yes, on the Goethe website.\nA: Does the model answer help with studying?\nB: A lot. It shows the perfect solution.",funFact:"Muster (sample/pattern) + Antwort (answer). A model answer. Die Musterantwort shows what a perfect response looks like. Goethe-Institut publishes Musterantworten for every exam level."},
{type:"teach",trg:"die Musterl\u00f6sung",src:"model solution",pos:"noun",gender:"f",note:"Muster + L\u00f6sung (solution). Similar to Musterantwort\nbut for problem-solving tasks. The pattern others should follow.",example:"A: Vergleich deine Antwort mit der Musterl\u00f6sung.\nB: Meine Antwort ist \u00e4hnlich.\nA: Die Musterl\u00f6sung zeigt den idealen Weg.\nB: Ich sehe, was ich besser machen kann.",exampleSrc:"A: Compare your answer with the model solution.\nB: My answer is similar.\nA: The model solution shows the ideal approach.\nB: I see what I can do better.",funFact:"Muster (sample/pattern) + L\u00f6sung (solution). Similar to Musterantwort but for problem-solving tasks. Muster means 'pattern' here: the pattern others should follow."},
{type:"teach",trg:"das L\u00f6sungsblatt",src:"answer sheet",pos:"noun",gender:"n",note:"L\u00f6sung (solution) + Blatt (sheet).\nWrite final answers here, not on the question paper.",example:"A: \u00dcbertrag die Antworten auf das L\u00f6sungsblatt.\nB: Alles auf das L\u00f6sungsblatt?\nA: Ja, nur das L\u00f6sungsblatt wird bewertet.\nB: Gut, ich \u00fcbertrage alles sorgf\u00e4ltig.",exampleSrc:"A: Transfer the answers to the answer sheet.\nB: Everything onto the answer sheet?\nA: Yes, only the answer sheet is graded.\nB: Good, I'll transfer everything carefully.",funFact:"L\u00f6sung (solution) + Blatt (sheet). Das L\u00f6sungsblatt. You write your final answers on the L\u00f6sungsblatt, not the question paper. Transfer carefully. Neuter because Blatt is neuter."},
{type:"teach",trg:"der L\u00fcckentext",src:"gap-fill text, cloze test",pos:"noun",gender:"m",note:"L\u00fccke (gap) + Text. You fill in the L\u00fccken (gaps).\nThe Sprachbausteine section is essentially a L\u00fcckentext.",example:"A: Was ist ein L\u00fcckentext?\nB: Ein Text mit L\u00fccken zum Ausf\u00fcllen.\nA: Wie bei den Sprachbausteinen?\nB: Genau. L\u00fcckentext ist der Fachbegriff.",exampleSrc:"A: What is a gap-fill text?\nB: A text with gaps to fill in.\nA: Like in the language building blocks section?\nB: Exactly. Gap-fill text is the technical term.",funFact:"L\u00fccke (gap) + Text. Der L\u00fcckentext. A cloze test. You fill in the L\u00fccken (gaps). The Sprachbausteine section is essentially a L\u00fcckentext."},
{type:"teach",trg:"die Mindmap",src:"mind map",pos:"noun",gender:"f",note:"English borrowing. German made it feminine,\npossibly by analogy with 'die Karte.' Used for essay brainstorming.",example:"A: Mach zuerst eine Mindmap.\nB: Warum eine Mindmap?\nA: Sie hilft, Ideen zu sortieren.\nB: Stimmt, dann schreibe ich strukturierter.",exampleSrc:"A: First make a mind map.\nB: Why a mind map?\nA: It helps to sort ideas.\nB: True, then I write more structured.",funFact:"English borrowing. Die Mindmap. German took the English word and made it feminine, possibly by analogy with 'die Karte/Landkarte.' Used in Pr\u00fcfungsvorbereitung to organize essay ideas."},
{type:"match",pairs:[{trg:"die Musterl\u00f6sung",src:"model solution"},{trg:"das L\u00f6sungsblatt",src:"answer sheet"},{trg:"der L\u00fcckentext",src:"gap-fill text, cloze test"},{trg:"die Mindmap",src:"mind map"}]},
{type:"teach",trg:"der Aufgabentyp",src:"task type",pos:"noun",gender:"m",note:"Aufgabe + Typ (type). Multiple choice, fill-in-the-blank,\nmatching, free writing: each is an Aufgabentyp.",example:"A: Welchen Aufgabentyp findest du am leichtesten?\nB: Multiple Choice.\nA: Jeder Aufgabentyp braucht eine eigene Strategie.\nB: Ja, man muss alle Aufgabentypen kennen.",exampleSrc:"A: Which task type do you find easiest?\nB: Multiple choice.\nA: Each task type needs its own strategy.\nB: Yes, you have to know all task types.",funFact:"Aufgabe (task) + Typ (type). Multiple choice, fill-in-the-blank, matching, free writing: each is an Aufgabentyp. Knowing the Aufgabentyp tells you what strategy to use."},
{type:"teach",trg:"die Auswahlaufgabe",src:"multiple-choice task",pos:"noun",gender:"f",note:"Auswahl (selection/choice) + Aufgabe.\nTip: eliminate wrong answers first, then choose.",example:"A: Die n\u00e4chste Aufgabe ist eine Auswahlaufgabe.\nB: Also Multiple Choice?\nA: Ja, eine Antwort aus vier M\u00f6glichkeiten.\nB: Ich eliminiere zuerst die falschen.",exampleSrc:"A: The next task is a multiple-choice task.\nB: So multiple choice?\nA: Yes, one answer from four options.\nB: I'll eliminate the wrong ones first.",funFact:"Auswahl (selection/choice) + Aufgabe. Die Auswahlaufgabe. A multiple-choice task. Tip: eliminate wrong answers first, then choose among the remaining."},
{type:"fb",s:"Auf dem {1} stehen die endg\u00fcltigen Antworten.",a:["L\u00f6sungsblatt"],opts:["L\u00f6sungsblatt","L\u00fcckentext","Aufgabentyp","Ma\u00dfstab"],hint:"The sheet where you write your final answers. L\u00f6sung (solution) + Blatt (sheet). Only this sheet is graded.",sSrc:"The final answers are on the answer sheet."},
{type:"fb",s:"Erstelle eine {1}, um deine Ideen visuell zu strukturieren.",a:["Mindmap"],opts:["Mindmap","Gliederung","Notiz","Aufgabentyp"],hint:"A visual diagram for organizing thoughts. Branches radiate from a central topic. From English.",sSrc:"Create a mind map to visually structure your ideas."}
]},
{id:"deu_r35l2b",title:"Wortfeld Pr\u00fcfung (Teil 2)",icon:"\ud83d\udcd6",xp:15,board:true,steps:[
{type:"intro",title:"Wortfeld Pr\u00fcfung (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"die Grammatik\u00fcbung",src:"grammar exercise",pos:"noun",gender:"f",note:"Grammatik + \u00dcbung (exercise). The Sprachbausteine section\nis a Grammatik\u00fcbung in disguise: grammar through context.",example:"A: Grammatik\u00fcbungen sind wichtig.\nB: Ja, Grammatik muss man \u00fcben.\nA: Die beste Grammatik\u00fcbung ist der L\u00fcckentext.\nB: Stimmt, Grammatik im Kontext.",exampleSrc:"A: Grammar exercises are important.\nB: Yes, you have to practice grammar.\nA: The best grammar exercise is the cloze test.\nB: True, grammar in context.",funFact:"Grammatik + \u00dcbung (exercise). Die Grammatik\u00fcbung. The Sprachbausteine section is a Grammatik\u00fcbung in disguise: testing grammar through context, not rules."},
{type:"teach",trg:"die \u00dcbungsaufgabe",src:"practice task",pos:"noun",gender:"f",note:"\u00dcbung (exercise) + Aufgabe. Doing many \u00dcbungsaufgaben\nbefore the exam is the key to success.",example:"A: Hast du genug \u00dcbungsaufgaben gemacht?\nB: Ja, bestimmt 50 St\u00fcck.\nA: Viele \u00dcbungsaufgaben machen die Muster automatisch.\nB: Genau, \u00dcbung macht den Meister.",exampleSrc:"A: Have you done enough practice tasks?\nB: Yes, at least 50 of them.\nA: Many practice tasks make the patterns automatic.\nB: Exactly, practice makes perfect.",funFact:"\u00dcbung (exercise) + Aufgabe. Die \u00dcbungsaufgabe. Doing many \u00dcbungsaufgaben before the exam is the key to success. Practice makes the patterns automatic."},
{type:"teach",trg:"ausf\u00fcllen",src:"to fill out, to complete (a form)",pos:"verb",gender:null,note:"Aus (out/completely) + f\u00fcllen (to fill). Separable.\n'F\u00fcllen Sie das L\u00f6sungsblatt aus.' The most common exam instruction.",example:"A: F\u00fcllen Sie das Formular aus.\nB: Alles ausf\u00fcllen?\nA: Ja, jedes Feld ausf\u00fcllen.\nB: Auch die R\u00fcckseite?",exampleSrc:"A: Fill out the form.\nB: Fill out everything?\nA: Yes, fill out every field.\nB: Also the back side?",funFact:"Aus (out/completely) + f\u00fcllen (to fill). Separable. On the exam: 'F\u00fcllen Sie das L\u00f6sungsblatt aus.' The most common instruction. To fill completely."},
{type:"teach",trg:"ankreuzen",src:"to mark with an X, to tick",pos:"verb",gender:null,note:"An (on) + kreuzen (to cross). Separable.\nEven digital exams use 'ankreuzen' metaphorically.",example:"A: Kreuzen Sie die richtige Antwort an.\nB: Nur eine Antwort ankreuzen?\nA: Ja, genau eine.\nB: Ich kreuze B an.",exampleSrc:"A: Mark the correct answer.\nB: Mark only one answer?\nA: Yes, exactly one.\nB: I'll mark B.",funFact:"An (on) + kreuzen (to cross). To mark with an X. Separable. 'Kreuzen Sie die richtige Antwort an.' The physical act of marking on paper. Even digital exams use 'ankreuzen' metaphorically."},
{type:"mc",q:"Was ist der Unterschied zwischen Musterantwort und Musterl\u00f6sung?",opts:["Es gibt keinen Unterschied, beide bedeuten dasselbe","Musterantwort ist f\u00fcr offene Fragen, Musterl\u00f6sung f\u00fcr Problemaufgaben","Musterantwort ist umgangssprachlich, Musterl\u00f6sung ist formell","Musterantwort ist falsch, Musterl\u00f6sung ist richtig"],ans:"Musterantwort ist f\u00fcr offene Fragen, Musterl\u00f6sung f\u00fcr Problemaufgaben",hint:"Both words begin with Muster (model/sample). The second part determines the context: one for open responses, the other for problem-based tasks."},
{type:"teach",trg:"sichten",src:"to review, to scan, to sort through",pos:"verb",gender:null,note:"From Sicht (sight/view). More formal than 'ansehen.'\nImplies systematic examination of documents.",example:"A: Zuerst das Material sichten.\nB: Alles sichten oder nur die Texte?\nA: Alles sichten, dann sortieren.\nB: Gut, ich sichte die Unterlagen.",exampleSrc:"A: First review the material.\nB: Review everything or just the texts?\nA: Review everything, then sort.\nB: Good, I'll review the documents.",funFact:"More formal than 'ansehen,' sichten implies systematic examination. 'Material sichten' (to review material) means scanning everything methodically. Built on the root Sicht (sight/view)."},
{type:"teach",trg:"sortieren",src:"to sort, to organize",pos:"verb",gender:null,note:"From French 'sortir' (to sort out). Before writing:\nbrainstorm, then sortieren. Order from chaos.",example:"A: Sortier zuerst deine Ideen.\nB: Wie sortiere ich am besten?\nA: Nach Wichtigkeit sortieren.\nB: Gut, die wichtigsten Punkte zuerst.",exampleSrc:"A: First sort your ideas.\nB: How do I sort best?\nA: Sort by importance.\nB: Good, the most important points first.",funFact:"Before writing the essay: brainstorm, then sortieren. Order from chaos. 'Die Ideen sortieren' (to sort the ideas). The verb was borrowed from French 'sortir' (to sort out)."},
{type:"mc",q:"Ein L\u00fcckentext ist...",opts:["ein Text zum \u00dcbersetzen und Paraphrasieren","ein Text zum Vorlesen und Nacherz\u00e4hlen","ein Text mit L\u00fccken zum Ausf\u00fcllen","ein Text zum Zusammenfassen und Gliedern"],ans:"ein Text mit L\u00fccken zum Ausf\u00fcllen",hint:"A fill-in-the-blank exercise. Lücke means gap. Each gap must be completed with the right word.",sSrc:"A gap-fill text is..."},
{type:"match",pairs:[{trg:"L\u00f6sungsblatt",src:"answer sheet"},{trg:"Musterantwort",src:"model answer"},{trg:"Bewertung",src:"assessment/grade"},{trg:"Aufgabenstellung",src:"task prompt"},{trg:"L\u00fcckentext",src:"gap-fill text"}]},
{type:"fb",s:"Bitte {1} Sie die richtige Antwort an.",a:["kreuzen"],opts:["kreuzen","f\u00fcllen","schreiben","lesen"],hint:"The separable verb for marking with an X. The prefix 'an' goes at the end.",sSrc:"Please mark the correct answer."},
{type:"drag_fill",s:"Zuerst die Aufgabenstellung {1}, dann die Schl\u00fcsselw\u00f6rter {2}, und am Ende das L\u00f6sungsblatt {3}.",blanks:{"1":"durchlesen","2":"markieren","3":"ausf\u00fcllen"},pool:["durchlesen","markieren","ausf\u00fcllen","korrigieren","ankreuzen","sichten"],hint:"First read the task completely. Then highlight key words. Finally fill in the answer sheet.",sSrc:"First read through the task prompt, then mark the keywords, and finally fill out the answer sheet."},
{type:"mc",q:"Auf fortgeschrittenem Niveau werden schriftliche Texte nach vier Kriterien bewertet. Was geh\u00f6rt NICHT dazu?",opts:["Inhalt (Qualit\u00e4t des Inhalts)","Textaufbau (Struktur und Gliederung)","Wortschatz (Breite des Wortschatzes)","Handschrift (Sch\u00f6nheit der Schrift)"],ans:"Handschrift (Sch\u00f6nheit der Schrift)",hint:"Content, structure, grammar, and vocabulary range count. The appearance of your penmanship does not.",sSrc:"At this level, written texts are evaluated by four criteria. What does NOT belong?"},
{type:"fb",s:"Die {1} zeigt, wie eine perfekte Antwort aussieht.",a:["Musterl\u00f6sung"],opts:["Musterl\u00f6sung","Aufgabenstellung","Bewertung","Grammatik\u00fcbung"],hint:"A compound noun. The first part means 'model' or 'template'. The second part means 'solution'. Together they form the ideal example answer.",sSrc:"The model solution shows what a perfect answer looks like."},
{type:"mc",q:"Bei einer Auswahlaufgabe soll man...",opts:["den gesamten Text vorlesen","die richtige Antwort ankreuzen","das L\u00f6sungsblatt zur\u00fcckgeben","die Aufgabe neu formulieren"],ans:"die richtige Antwort ankreuzen",hint:"Auswahl = selection. Think about the physical gesture used to indicate your choice on paper."}
]},
{id:"deu_r35l3",title:"Indem du schreibst",icon:"\u270d\ufe0f",xp:15,board:true,steps:[
{type:"intro",title:"Indem du schreibst",desc:"Verumius sits in the exam room. The writing task lies before him. Learn modal clauses and the language of argumentation.",goals:["Master modal clauses: indem, dadurch dass, ohne dass, anstatt dass","Structure a B2 essay","Learn the technical language of argumentation"]},
{type:"teach",trg:"die Argumentation",src:"argumentation, making a case",pos:"noun",gender:"f",note:"From Latin 'argumentatio.' At B2: claim, evidence,\ncounterargument, conclusion. Structured reasoning.",example:"A: Deine Argumentation ist \u00fcberzeugend.\nB: Danke, ich habe Beispiele gegeben.\nA: Gute Argumentation braucht Struktur.\nB: These, Beispiele, Gegenargument, Fazit.",exampleSrc:"A: Your argumentation is convincing.\nB: Thanks, I gave examples.\nA: Good argumentation needs structure.\nB: Thesis, examples, counterargument, conclusion.",funFact:"At B2 level, you must build a logical Argumentation: claim, evidence, counterargument, conclusion. Not just opinions, but structured reasoning. Latin root: 'argumentatio.'"},
{type:"teach",trg:"die Einleitung",src:"introduction",pos:"noun",gender:"f",note:"Ein (in/into) + Leitung (leading). Leads the reader\nINTO the topic. Two to three sentences.",example:"A: Die Einleitung ist zu lang.\nB: Wie lang soll die Einleitung sein?\nA: Zwei bis drei S\u00e4tze.\nB: Okay, ich k\u00fcrze die Einleitung.",exampleSrc:"A: The introduction is too long.\nB: How long should the introduction be?\nA: Two to three sentences.\nB: Okay, I'll shorten the introduction.",funFact:"Ein (in/into) + Leitung (leading). Die Einleitung leads the reader INTO the topic. A good Einleitung states the topic, gives context, and hints at your position."},
{type:"teach",trg:"der Hauptteil",src:"main body (of an essay)",pos:"noun",gender:"m",note:"Haupt (main) + Teil (part). Contains arguments, examples,\nand counterarguments. The longest section.",example:"A: Im Hauptteil kommen die Argumente.\nB: Wie viele Argumente?\nA: Mindestens drei im Hauptteil.\nB: Pro und Kontra im Hauptteil?",exampleSrc:"A: The arguments go in the main body.\nB: How many arguments?\nA: At least three in the main body.\nB: Pro and con in the main body?",funFact:"Haupt (main) + Teil (part). Der Hauptteil contains your arguments, examples, and counterarguments. The longest section. 'Im Hauptteil entwickle ich meine Argumentation.'"},
{type:"teach",trg:"der Schluss",src:"conclusion, ending",pos:"noun",gender:"m",note:"From schlie\u00dfen (to close). 'Zum Schluss' signals the end.\nNot just a repeat of the Einleitung.",example:"A: Zum Schluss fasse ich zusammen.\nB: Was kommt in den Schluss?\nA: Zusammenfassung und eigene Meinung.\nB: Der Schluss ist kurz aber wichtig.",exampleSrc:"A: In conclusion, I summarize.\nB: What goes in the conclusion?\nA: Summary and personal opinion.\nB: The conclusion is short but important.",funFact:"'Zum Schluss' (in conclusion) signals the end. A good Schluss summarizes and takes a final position, never just repeating the Einleitung. The root verb 'schliessen' means to close."},
{type:"fb",s:"Deine {1} muss \u00fcberzeugend sein: These, Beispiele und Gegenargumente.",a:["Argumentation"],opts:["Argumentation","Einleitung","Textsorte","Zusammenfassung"],hint:"The art of building a logical case. From Latin 'argumentatio.' Structured reasoning with claims, examples, and evidence.",sSrc:"Your argumentation must be convincing: thesis, examples, and counterarguments."},
{type:"teach",trg:"das Fazit",src:"conclusion, final assessment",pos:"noun",gender:"n",note:"From Latin 'facit' (it makes/amounts to). More formal\nthan Schluss. 'Mein Fazit ist...' (My conclusion is...)",example:"A: Was ist dein Fazit?\nB: Mein Fazit: Digitale Medien sind n\u00fctzlich.\nA: Ein gutes Fazit fasst alles zusammen.\nB: Ja, das Fazit ist die Quintessenz.",exampleSrc:"A: What is your conclusion?\nB: My conclusion: digital media are useful.\nA: A good conclusion summarizes everything.\nB: Yes, the conclusion is the quintessence.",funFact:"More formal than Schluss, das Fazit is the bottom line of your argument. 'Mein Fazit ist...' (My conclusion is...). The word traces back to Latin 'facit' (it makes/amounts to)."},
{type:"teach",trg:"die Textsorte",src:"text type, genre",pos:"noun",gender:"f",note:"Text + Sorte (type/kind). Essay, letter, report, email:\neach is a Textsorte with its own conventions.",example:"A: Welche Textsorte musst du schreiben?\nB: Einen argumentativen Aufsatz.\nA: Jede Textsorte hat eigene Regeln.\nB: Ja, ein Brief ist anders als ein Aufsatz.",exampleSrc:"A: Which text type do you have to write?\nB: An argumentative essay.\nA: Each text type has its own rules.\nB: Yes, a letter is different from an essay.",funFact:"Text + Sorte (type/kind). Die Textsorte. Essay, letter, report, email: each is a Textsorte with its own conventions. The exam tells you which Textsorte to write."},
{type:"teach",trg:"der Satzbau",src:"sentence structure",pos:"noun",gender:"m",note:"Satz (sentence) + Bau (construction). German Satzbau\nwith verb-second and verb-final makes the language unique.",example:"A: Dein Satzbau ist gut.\nB: Danke, ich \u00fcbe den Satzbau.\nA: Guter Satzbau bedeutet gute Noten.\nB: Ja, Verb-Zweit und Verb-Letzt.",exampleSrc:"A: Your sentence structure is good.\nB: Thanks, I practice sentence structure.\nA: Good sentence structure means good grades.\nB: Yes, verb-second and verb-final.",funFact:"Satz (sentence) + Bau (construction). German Satzbau with its verb-second and verb-final rules is what makes the language unique. Good Satzbau = good grade."},
{type:"teach",trg:"der Ausdruck",src:"expression, phrasing",pos:"noun",gender:"m",note:"Aus (out) + Druck (pressing). 'Einen guten Ausdruck haben'\nmeans expressing yourself well. Precision matters.",example:"A: Dein Ausdruck ist sehr pr\u00e4zise.\nB: Danke, ich achte auf guten Ausdruck.\nA: Ausdruck ist ein Bewertungskriterium.\nB: Ja, die Wortwahl z\u00e4hlt.",exampleSrc:"A: Your expression is very precise.\nB: Thanks, I pay attention to good expression.\nA: Expression is an assessment criterion.\nB: Yes, word choice counts.",funFact:"Aus (out) + Druck (pressing). Der Ausdruck. 'Einen guten Ausdruck haben' (to express yourself well). Examiners grade Ausdruck: your choice of words and phrases. Precision matters."},
{type:"mc",q:"Was ist der Unterschied zwischen Einleitung, Hauptteil und Schluss?",opts:["Einleitung = Zusammenfassung, Hauptteil = Meinung, Schluss = Beispiele","Einleitung = Thema vorstellen, Hauptteil = Argumente, Schluss = Fazit","Alle drei Teile enthalten genau dieselben Informationen","Einleitung = l\u00e4ngster Teil, Hauptteil = k\u00fcrzester, Schluss = mittellang"],ans:"Einleitung = Thema vorstellen, Hauptteil = Argumente, Schluss = Fazit",hint:"Three parts of a German essay: the first introduces the topic, the middle develops arguments, and the last summarizes with a position."}
]},
{id:"deu_r35l3b",title:"Indem du schreibst (Teil 2)",icon:"\u270d\ufe0f",xp:15,board:true,steps:[
{type:"intro",title:"Indem du schreibst (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"die Zusammenfassung",src:"summary",pos:"noun",gender:"f",note:"Zusammen (together) + Fassung (version/grasp).\nBrings everything together into a compressed version.",example:"A: Schreib eine Zusammenfassung des Textes.\nB: In eigenen Worten?\nA: Ja, eine kurze Zusammenfassung.\nB: Okay, die wichtigsten Punkte zusammenfassen.",exampleSrc:"A: Write a summary of the text.\nB: In your own words?\nA: Yes, a short summary.\nB: Okay, summarize the most important points.",funFact:"Zusammen (together) + Fassung (version/grasp). Die Zusammenfassung brings everything together into a compressed version. 'Eine Zusammenfassung schreiben' is a core B2 skill."},
{type:"teach",trg:"nacherz\u00e4hlen",src:"to retell, to narrate after hearing",pos:"verb",gender:null,note:"Nach (after/re-) + erz\u00e4hlen (to tell). Separable.\nHear or read something, then nacherz\u00e4hlen in your own words.",example:"A: Erz\u00e4hl den Text nach.\nB: In eigenen Worten?\nA: Ja, den Inhalt nacherz\u00e4hlen.\nB: Also, es ging um digitale Medien...",exampleSrc:"A: Retell the text.\nB: In my own words?\nA: Yes, retell the content.\nB: So, it was about digital media...",funFact:"Nach (after/re-) + erz\u00e4hlen (to tell). Separable. You hear or read something, then nacherz\u00e4hlen it in your own words. A core exam skill."},
{type:"teach",trg:"paraphrasieren",src:"to paraphrase",pos:"verb",gender:null,note:"From Greek 'paraphrasis' (restatement). Same word\ninternationally. Saying the same thing differently.",example:"A: Kannst du den Satz paraphrasieren?\nB: 'Man sollte' statt 'es ist notwendig.'\nA: Gut paraphrasiert.\nB: Paraphrasieren zeigt Wortschatz.",exampleSrc:"A: Can you paraphrase the sentence?\nB: 'One should' instead of 'it is necessary.'\nA: Well paraphrased.\nB: Paraphrasing shows vocabulary range.",funFact:"The B2 skill of saying the same thing differently. Essential for avoiding plagiarism and demonstrating vocabulary range. Nearly identical across all languages, from Greek 'paraphrasis' (restatement)."},
{type:"teach",trg:"zusammenfassen",src:"to summarize",pos:"verb",gender:null,note:"Zusammen + fassen (to grasp). Separable.\nLiterally: to grasp things together into one.",example:"A: Fass den Text zusammen.\nB: In zwei S\u00e4tzen?\nA: Ja, kurz zusammenfassen.\nB: Der Text handelt von Bildung und Technologie.",exampleSrc:"A: Summarize the text.\nB: In two sentences?\nA: Yes, summarize briefly.\nB: The text is about education and technology.",funFact:"Zusammen (together) + fassen (to grasp). Separable. Literally: to grasp things together into one. The verb form of Zusammenfassung."},
{type:"teach",trg:"\u00fcberarbeiten",src:"to revise, to rework",pos:"verb",gender:null,note:"\u00dcber (over) + arbeiten (to work). Not separable (inseparable \u00fcber-).\nFirst draft, then \u00fcberarbeiten.",example:"A: Hast du den Text \u00fcberarbeitet?\nB: Ja, ich habe ihn zweimal \u00fcberarbeitet.\nA: \u00dcberarbeiten verbessert die Qualit\u00e4t.\nB: Ja, der erste Entwurf ist nie perfekt.",exampleSrc:"A: Did you revise the text?\nB: Yes, I revised it twice.\nA: Revising improves the quality.\nB: Yes, the first draft is never perfect.",funFact:"\u00dcber (over) + arbeiten (to work). Not separable (inseparable \u00fcber-). To go OVER your work again and improve it. First draft, then \u00fcberarbeiten."},
{type:"match",pairs:[{trg:"nacherz\u00e4hlen",src:"to retell, to narrate after hearing"},{trg:"paraphrasieren",src:"to paraphrase"},{trg:"zusammenfassen",src:"to summarize"},{trg:"\u00fcberarbeiten",src:"to revise, to rework"}]},
{type:"teach",trg:"umformulieren",src:"to rephrase, to reformulate",pos:"verb",gender:null,note:"Um (re-/around) + formulieren (to formulate). Separable.\nChange the form while keeping the meaning.",example:"A: Der Satz klingt komisch.\nB: Dann formulier ihn um.\nA: Okay, ich formuliere ihn um.\nB: Besser. Umformulieren hilft.",exampleSrc:"A: The sentence sounds odd.\nB: Then rephrase it.\nA: Okay, I'll rephrase it.\nB: Better. Rephrasing helps.",funFact:"Um (re-/around) + formulieren (to formulate). Separable. When your sentence sounds clunky: umformulieren. Change the form while keeping the meaning."},
{type:"fb",s:"Zuerst die Ideen sammeln, dann den Text {1}.",a:["zusammenfassen"],opts:["zusammenfassen","nacherz\u00e4hlen","paraphrasieren","\u00fcberarbeiten"],hint:"The separable verb meaning to bring everything together into a compressed version. Zusammen + fassen.",sSrc:"First collect the ideas, then summarize the text."},
{type:"teach",trg:"gliedern",src:"to structure, to divide into sections",pos:"verb",gender:null,note:"From Glied (limb/member/section). Like a body divided\ninto its limbs, a text divided into its parts.",example:"A: Gliedere den Text in Abschnitte.\nB: Wie viele Abschnitte?\nA: Drei: Einleitung, Hauptteil, Schluss.\nB: Gut gegliedert, gut geschrieben.",exampleSrc:"A: Divide the text into sections.\nB: How many sections?\nA: Three: introduction, main body, conclusion.\nB: Well structured, well written.",funFact:"Like a body divided into its limbs, a text divided into its parts. Gliederung (outline) comes from Glied (limb/section). 'Den Text in Abschnitte gliedern' is the first step of good writing."},
{type:"teach",trg:"herausarbeiten",src:"to work out, to highlight",pos:"verb",gender:null,note:"Heraus (out) + arbeiten (to work). Separable.\nYou dig the meaning OUT through effort.",example:"A: Arbeite die Hauptaussage heraus.\nB: Was ist die Hauptaussage?\nA: Das musst du herausarbeiten.\nB: Also die zentrale These finden.",exampleSrc:"A: Work out the main message.\nB: What is the main message?\nA: You have to work that out.\nB: So find the central thesis.",funFact:"Heraus (out) + arbeiten (to work). Separable. 'Die Hauptaussage herausarbeiten' (to work out the main message). You dig the meaning OUT through effort."},
{type:"teach",trg:"schriftlich",src:"written, in writing",pos:"adj",gender:null,note:"Schrift (writing/script) + -lich. Opposite of 'm\u00fcndlich' (oral).\n'Bitte schriftlich best\u00e4tigen.'",example:"A: Ist die Pr\u00fcfung schriftlich?\nB: Teils schriftlich, teils m\u00fcndlich.\nA: Welcher Teil ist schriftlich?\nB: Lesen, H\u00f6ren und Schreiben sind schriftlich.",exampleSrc:"A: Is the exam written?\nB: Partly written, partly oral.\nA: Which part is written?\nB: Reading, listening, and writing are written.",funFact:"Schrift (writing/script) + -lich. 'Schriftliche Pr\u00fcfung' (written exam). The opposite of 'm\u00fcndlich' (oral). 'Bitte schriftlich best\u00e4tigen' (please confirm in writing)."},
{type:"tip",title:"Modals\u00e4tze: Wie man sagt, AUF WELCHE WEISE etwas geschieht",text:"Manner clauses answer the question: 'Auf welche Weise?' (In what way?)\n\nKey connectors:\n\n'indem' (by doing X)\nIndem ich \u00fcberarbeite, verbessere ich den Text.\n(By revising, I improve the text.)\n\n'dadurch dass' (through the fact that)\nDadurch dass er \u00fcbt, wird er besser.\n(Through practicing, he gets better.)\n\n'ohne dass' (without doing)\nEr besteht die Pr\u00fcfung, ohne dass er nervoes wird.\n(He passes the exam without getting nervous.)\n\n'anstatt dass' (instead of doing)\nAnstatt dass er aufgibt, arbeitet er weiter.\n(Instead of giving up, he keeps working.)\n\nPosition: The verb goes to the END of the dass-clause.\n'Indem' is the most common and versatile connector.",deepDive:{title:"Modals\u00e4tze: Formation and usage",text:"Modals\u00e4tze express HOW an action is carried out. They answer the question 'Auf welche Weise?' (In what way?).\n\n'Indem' is the most common. It introduces a manner clause: 'Indem ich lerne, werde ich besser.' The verb goes to the end of the indem-clause.\n\n'Ohne dass' and 'anstatt dass' can be shortened with 'zu + Infinitiv' when the subject is the same: 'Er ging, ohne sich zu verabschieden.' (He left without saying goodbye.)\n\n'Dadurch dass' is slightly more formal and emphasizes the method or means. It can also be split: 'Dadurch, dass er \u00fcbt, wird er besser.'"}},
{type:"verb_table",title:"Modals\u00e4tze: Konnektor\u00fcbersicht",groups:[{label:"Modals\u00e4tze (Manner clauses)",rows:[{pronoun:"indem",form:"by (doing something)",src:"Indem ich lerne, werde ich besser."},{pronoun:"dadurch dass",form:"through the fact that",src:"Dadurch dass er \u00fcbt, verbessert er sich."},{pronoun:"ohne dass",form:"without (doing)",src:"Er ging, ohne dass er sich verabschiedete."},{pronoun:"anstatt dass",form:"instead of (doing)",src:"Anstatt dass er lernt, spielt er."}]}]},
{type:"mc",q:"Welcher Satz enth\u00e4lt einen Modalsatz?",opts:["Ich bekomme gute Noten, weil ich regelm\u00e4\u00dfig und intensiv lerne.","Indem ich strukturiert schreibe, bekomme ich gute Noten.","Obwohl ich nerv\u00f6s bin, schreibe ich nach wie vor gut.","Wenn ich t\u00e4glich lerne, bekomme ich entsprechend gute Noten."],ans:"Indem ich strukturiert schreibe, bekomme ich gute Noten.",hint:"One connector specifically answers the question HOW a result comes about. By doing X, Y happens.",sSrc:"Which sentence contains a manner clause?"},
{type:"fb",s:"{1} ich die Schl\u00fcsselw\u00f6rter markiere, finde ich die Antwort schneller.",a:["Indem"],opts:["Indem","Weil","Obwohl","Wenn"],hint:"Which connector answers the question HOW? It introduces a manner clause describing the method used to achieve a goal.",sSrc:"By marking the keywords, I find the answer faster."},
{type:"drag_fill",s:"Ein guter Aufsatz hat eine {1}, einen {2} und einen {3}.",blanks:{"1":"Einleitung","2":"Hauptteil","3":"Schluss"},pool:["Einleitung","Hauptteil","Schluss","Anfang","Mitte","Ende"],hint:"The three formal parts of a German essay. The technical terms, not the everyday words.",sSrc:"A good essay has an introduction, a main body, and a conclusion."},
{type:"mc",q:"'Den Inhalt in eigenen Worten wiedergeben' bedeutet dasselbe wie...",opts:["zusammenfassen","paraphrasieren","nacherz\u00e4hlen","korrigieren"],ans:"paraphrasieren",hint:"Rendering content in your own words: the academic verb of Greek origin.",sSrc:"'Rendering content in your own words' means the same as..."},
{type:"mc",q:"Was bedeutet 'umformulieren'?",opts:["to rephrase, to reformulate","to revise, to rework","sentence structure","conclusion, ending"],ans:"to rephrase, to reformulate",hint:"um- (around/re-) + formulieren (to formulate). To say the same thing in different words."},
{type:"fb",s:"Wie sagt man 'to structure, to divide into sections' auf Deutsch? {1}",a:["gliedern"],opts:["gliedern","die Argumentation","herausarbeiten","der Satzbau"],hint:"From Glied (limb/section). To divide a text into logical parts, like limbs of a body.",sSrc:"How do you say 'to structure, to divide into sections' in German?"},
{type:"mc",q:"Was bedeutet 'herausarbeiten'?",opts:["to work out, to highlight","introduction","to structure, to divide into sections","conclusion, final assessment"],ans:"to work out, to highlight",hint:"heraus- (out) + arbeiten. To extract key points from material, to bring what matters to the surface."},
{type:"fb",s:"Ist die Pr\\u00fcfung {1}?",a:["schriftlich"],opts:["schriftlich","die Textsorte","\\u00fcberarbeiten","herausarbeiten"],hint:"From Schrift (writing/script). The -lich suffix: in written form, on paper.",sSrc:"Is the exam written?"}
]},
{id:"deu_r35l4",title:"S\u00e4mtliche Aufgaben",icon:"\ud83d\udcda",xp:15,board:true,steps:[
{type:"intro",title:"S\u00e4mtliche Aufgaben",desc:"Extended indefinite pronouns for formal texts. Reading strategies for reading comprehension. Academic vocabulary.",goals:["Master extended indefinite pronouns for formal contexts","Understand reading strategies: global and detailed comprehension","Build academic vocabulary","Review Modalsatze in new contexts"]},
{type:"teach",trg:"s\u00e4mtliche",src:"all, every single one (emphatic)",pos:"adj",gender:null,note:"From Samt (together with). More emphatic than 'alle.'\nUsed in formal and legal language.",example:"A: S\u00e4mtliche Aufgaben m\u00fcssen bearbeitet werden.\nB: Wirklich s\u00e4mtliche?\nA: Ja, s\u00e4mtliche. Ohne Ausnahme.\nB: Dann fange ich sofort an.",exampleSrc:"A: All tasks must be completed.\nB: Really all of them?\nA: Yes, every single one. Without exception.\nB: Then I'll start right away.",funFact:"More emphatic than 'alle,' saemtliche means every single one without exception. Used in formal and legal language. Declines like a regular adjective. Derives from Samt (together with)."},
{type:"teach",trg:"jegliche",src:"any whatsoever, all manner of",pos:"adj",gender:null,note:"From jeglich (any/every). Stronger than 'jede.'\nFormal, slightly old-fashioned. Common in rules and bans.",example:"A: Jegliche Hilfsmittel sind verboten.\nB: Auch W\u00f6rterb\u00fccher?\nA: Ja, jegliche Hilfsmittel.\nB: Also wirklich gar nichts erlaubt.",exampleSrc:"A: Any aids whatsoever are forbidden.\nB: Even dictionaries?\nA: Yes, any aids whatsoever.\nB: So really nothing at all allowed.",funFact:"'Jegliche Hilfsmittel sind verboten' is the exam instruction that bans everything. Stronger than 'jede,' slightly old-fashioned but still common in rules. Built on the archaic 'jeglich' (any/every)."},
{type:"teach",trg:"irgendein",src:"some (unspecified), any",pos:"adj",gender:null,note:"Irgend (some-) + ein (a/an). The vaguest possible article.\nDeclines like 'ein': irgendeinen, irgendeiner, irgendeinem.",example:"A: Hast du irgendeine Idee?\nB: Irgendeine? Ja, vielleicht.\nA: Irgendein Vorschlag w\u00e4re gut.\nB: Lass mich nachdenken.",exampleSrc:"A: Do you have any idea?\nB: Any? Yes, maybe.\nA: Any suggestion would be good.\nB: Let me think.",funFact:"Irgend (some-) + ein (a/an). The vaguest possible article. It could be any one. Declines like 'ein': irgendeinen, irgendeiner, irgendeinem."},
{type:"teach",trg:"irgendwelche",src:"some (plural, unspecified), any",pos:"adj",gender:null,note:"Irgend + welche (which/some). The plural of irgendein.\nUsed for polite inquiry.",example:"A: Gibt es irgendwelche Fragen?\nB: Ja, irgendwelche Fragen zum Ablauf.\nA: Haben Sie irgendwelche Bedenken?\nB: Nein, keine.",exampleSrc:"A: Are there any questions?\nB: Yes, some questions about the procedure.\nA: Do you have any concerns?\nB: No, none.",funFact:"Irgend + welche (which/some). The plural of irgendein. Vague and open. 'Gibt es irgendwelche Fragen?' Used for polite inquiry when you expect the answer might be yes."},
{type:"teach",trg:"manch ein",src:"many a, some",pos:"adj",gender:null,note:"Manch (some/many a) + ein. Literary and slightly formal.\nEmphasizes the individual within the group.",example:"A: Manch ein Student hat Pr\u00fcfungsangst.\nB: Ja, manch einer schafft es trotzdem.\nA: Manch ein Problem l\u00f6st sich von selbst.\nB: Stimmt, manchmal muss man nur warten.",exampleSrc:"A: Many a student has exam anxiety.\nB: Yes, many a one manages it anyway.\nA: Many a problem solves itself.\nB: True, sometimes you just have to wait.",funFact:"Manch (some/many a) + ein. Literary and slightly formal. 'Manch ein Student hat Pr\u00fcfungsangst.' Emphasizes the individual within the group. 'Many a student' has the same feel in English."},
{type:"fb",s:"{1} Hilfsmittel sind w\u00e4hrend der Pr\u00fcfung streng verboten.",a:["Jegliche"],opts:["Jegliche","Irgendwelche","Manch","Allerhand"],hint:"The strongest formal word for 'any whatsoever.' Used in exam rules and regulations. Stronger than 'jede.'",sSrc:"Any aids whatsoever are strictly forbidden during the exam."},
{type:"teach",trg:"jedweder",src:"every single, any whatsoever",pos:"adj",gender:null,note:"Jed- (every) + weder (archaic 'which'). Very formal, almost legal.\nStronger than 'jeder.' Found in regulations.",example:"A: Jedweder Betrug wird bestraft.\nB: Jedweder? Das klingt streng.\nA: Ja, jedweder Versto\u00df hat Konsequenzen.\nB: Verstanden, kein Risiko.",exampleSrc:"A: Any cheating whatsoever will be punished.\nB: Any whatsoever? That sounds strict.\nA: Yes, any violation has consequences.\nB: Understood, no risk.",funFact:"'Jedweder Betrug wird bestraft.' Very formal, almost legal. Stronger than 'jeder.' Built on jed- (every) + the archaic weder (which). You will encounter it in regulations and exam rules."},
{type:"teach",trg:"allerhand",src:"all sorts of, quite a lot",pos:"adj",gender:null,note:"Aller (all) + Hand (hand). Colloquial but useful.\n'Allerhand!' as exclamation means 'quite something!'",example:"A: Da gibt es allerhand zu lernen.\nB: Allerhand Vokabeln und Grammatik.\nA: Allerhand!\nB: Ja, ganz sch\u00f6n viel.",exampleSrc:"A: There's all sorts of things to learn.\nB: All sorts of vocabulary and grammar.\nA: Quite something!\nB: Yes, quite a lot.",funFact:"Aller (all) + Hand (hand). 'Da gibt es allerhand zu lernen.' Colloquial but useful. 'Allerhand!' as an exclamation means 'quite something!' Literally 'of all hands.'"},
{type:"teach",trg:"allerlei",src:"all sorts of, various",pos:"adj",gender:null,note:"Aller + lei (type/sort, from Latin). Slightly more formal\nthan 'allerhand.' Has a fairy-tale quality.",example:"A: Allerlei Fragen kommen in der Pr\u00fcfung vor.\nB: Allerlei Themen auch?\nA: Ja, allerlei Textsorten und Themen.\nB: Dann muss ich allerlei \u00fcben.",exampleSrc:"A: All sorts of questions appear in the exam.\nB: All sorts of topics too?\nA: Yes, all sorts of text types and topics.\nB: Then I have to practice all sorts of things.",funFact:"Aller + lei (type/sort, from Latin). 'Allerlei Fragen kommen im H\u00f6rverstehen vor.' Slightly more formal than allerhand. Same meaning. Has a fairy-tale quality."},
{type:"mc",q:"Welches Wort bedeutet 'alle, ohne Ausnahme' und klingt formeller als 'alle'?",opts:["irgendwelche","s\u00e4mtliche","manch ein","allerhand"],ans:"s\u00e4mtliche",hint:"More emphatic than 'alle.' Used in formal and legal language. From Samt (together with). Declines like a regular adjective."}
]},
{id:"deu_r35l4b",title:"S\u00e4mtliche Aufgaben (Teil 2)",icon:"\ud83d\udcda",xp:15,board:true,steps:[
{type:"intro",title:"S\u00e4mtliche Aufgaben (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"die Hauptaussage",src:"main message, key point",pos:"noun",gender:"f",note:"Haupt (main) + Aussage (statement). The fundamental\nreading comprehension question: Was ist die Hauptaussage?",example:"A: Was ist die Hauptaussage des Textes?\nB: Der Autor fordert mehr Umweltschutz.\nA: Genau, die Hauptaussage erkennen ist wichtig.\nB: Daf\u00fcr muss man den ganzen Text lesen.",exampleSrc:"A: What is the main message of the text?\nB: The author demands more environmental protection.\nA: Exactly, recognizing the main message is important.\nB: For that you have to read the whole text.",funFact:"Haupt (main) + Aussage (statement). 'Was ist die Hauptaussage des Textes?' is the fundamental reading comprehension question. Die Hauptaussage."},
{type:"teach",trg:"das Schl\u00fcsselwort",src:"keyword",pos:"noun",gender:"n",note:"Schl\u00fcssel (key) + Wort (word). Marking Schl\u00fcsselw\u00f6rter\nis the first step in reading comprehension.",example:"A: Markier die Schl\u00fcsselw\u00f6rter im Text.\nB: Welche W\u00f6rter sind Schl\u00fcsselw\u00f6rter?\nA: Die wichtigsten Begriffe.\nB: Also 'Umwelt,' 'Schutz,' 'Gefahr.'",exampleSrc:"A: Mark the keywords in the text.\nB: Which words are keywords?\nA: The most important terms.\nB: So 'environment,' 'protection,' 'danger.'",funFact:"Schl\u00fcssel (key) + Wort (word). Marking Schl\u00fcsselw\u00f6rter is the first step in reading comprehension. They unlock the meaning of the text. The key to the text, literally."},
{type:"teach",trg:"der Absatz",src:"paragraph",pos:"noun",gender:"m",note:"Ab (off) + Satz (set/sentence). Also means 'heel' (shoe)\nand 'sales' (commerce). Context decides.",example:"A: Lies den zweiten Absatz.\nB: Nur den zweiten Absatz?\nA: Ja, die Antwort steht im zweiten Absatz.\nB: Okay, ich lese den Absatz nochmal.",exampleSrc:"A: Read the second paragraph.\nB: Only the second paragraph?\nA: Yes, the answer is in the second paragraph.\nB: Okay, I'll read the paragraph again.",funFact:"Ab (off) + Satz (set/sentence). Der Absatz. Also means 'heel' (of a shoe) and 'sales' (in commerce). Three completely different meanings for one word. Context decides."},
{type:"teach",trg:"die \u00dcberschrift",src:"heading, title",pos:"noun",gender:"f",note:"\u00dcber (over/above) + Schrift (writing). The writing\nthat sits ABOVE the text. Gives the first hint about content.",example:"A: Was sagt die \u00dcberschrift?\nB: 'Klimawandel und Bildung.'\nA: Die \u00dcberschrift gibt den ersten Hinweis.\nB: Ja, das Thema ist klar.",exampleSrc:"A: What does the heading say?\nB: 'Climate change and education.'\nA: The heading gives the first hint.\nB: Yes, the topic is clear.",funFact:"\u00dcber (over/above) + Schrift (writing). Die \u00dcberschrift. 'Die \u00dcberschrift gibt den ersten Hinweis auf den Inhalt.' The writing that sits ABOVE the text."},
{type:"teach",trg:"das Globalverstehen",src:"gist comprehension, global understanding",pos:"noun",gender:"n",note:"Global + Verstehen. The first read: what is the text\nABOUT? No details yet. Just the big picture.",example:"A: Zuerst das Globalverstehen.\nB: Was bedeutet Globalverstehen?\nA: Den Text grob verstehen. Worum geht es?\nB: Also das Thema erfassen.",exampleSrc:"A: First global comprehension.\nB: What does global comprehension mean?\nA: Understanding the text roughly. What is it about?\nB: So grasping the topic.",funFact:"Global + Verstehen. Das Globalverstehen. The first read: what is the text ABOUT? No details yet. Just the big picture."},
{type:"match",pairs:[{trg:"das Schl\u00fcsselwort",src:"keyword"},{trg:"der Absatz",src:"paragraph"},{trg:"die \u00dcberschrift",src:"heading, title"},{trg:"das Globalverstehen",src:"gist comprehension, global understanding"}]},
{type:"teach",trg:"das Detailverstehen",src:"detailed comprehension",pos:"noun",gender:"n",note:"Detail + Verstehen. The second read: what exactly does\nparagraph 3 say? Specific information extraction.",example:"A: Jetzt kommt das Detailverstehen.\nB: Was genau steht in Absatz 3?\nA: Detailverstehen hei\u00dft: genaue Informationen finden.\nB: Okay, ich lese genauer.",exampleSrc:"A: Now comes the detailed comprehension.\nB: What exactly is in paragraph 3?\nA: Detailed comprehension means: finding exact information.\nB: Okay, I'll read more carefully.",funFact:"Detail + Verstehen. Das Detailverstehen. The second read: what exactly does paragraph 3 say? Specific information extraction."},
{type:"teach",trg:"erkennen",src:"to recognize, to identify",pos:"verb",gender:null,note:"Er- + kennen (to know). Not separable. You kennen something\nand er-kennen it when you see it again. Re-cognition.",example:"A: Kannst du die Hauptaussage erkennen?\nB: Ja, ich erkenne sie im ersten Absatz.\nA: Gut erkannt.\nB: Man muss genau lesen, um sie zu erkennen.",exampleSrc:"A: Can you identify the main message?\nB: Yes, I recognize it in the first paragraph.\nA: Well spotted.\nB: You have to read carefully to recognize it.",funFact:"Er- + kennen (to know). Not separable. You kennen (know) something and er-kennen (recognize) it when you see it again. Re-cognition. 'Die Hauptaussage erkennen.'"},
{type:"teach",trg:"erschlie\u00dfen",src:"to deduce, to infer",pos:"verb",gender:null,note:"Er- + schlie\u00dfen (to close/conclude). Not separable.\nA critical reading skill: meaning from context.",example:"A: Was bedeutet dieses Wort?\nB: Ich kenne es nicht, aber ich kann es erschlie\u00dfen.\nA: Aus dem Kontext erschlie\u00dfen?\nB: Ja, die S\u00e4tze davor helfen.",exampleSrc:"A: What does this word mean?\nB: I don't know it, but I can infer it.\nA: Infer from context?\nB: Yes, the sentences before help.",funFact:"Er- + schlie\u00dfen (to close/conclude). Not separable. When you do not know a word, you erschlie\u00dfen its meaning from context. A critical reading skill at B2."},
{type:"fb",s:"Wenn ein Wort unbekannt ist, kann man es aus dem Kontext {1}.",a:["erschlie\u00dfen"],opts:["erkennen","einordnen","erschlie\u00dfen","markieren"],hint:"To unlock meaning from surrounding context. Ent- + schl\u00fcsseln, from Schl\u00fcssel (key). Deducing what a word means without a dictionary.",sSrc:"When a word is unknown, you can infer it from context."},
{type:"teach",trg:"einordnen",src:"to classify, to categorize",pos:"verb",gender:null,note:"Ein (in/into) + ordnen (to order/organize). Separable.\nYou take something and ordnen it into the right place.",example:"A: Ordne die Informationen ein.\nB: In welche Kategorie?\nA: In 'pro' und 'kontra' einordnen.\nB: Okay, ich ordne die Argumente ein.",exampleSrc:"A: Classify the information.\nB: Into which category?\nA: Classify into 'pro' and 'con.'\nB: Okay, I'll classify the arguments.",funFact:"Ein (in/into) + ordnen (to order/organize). Separable. 'Die Information einordnen' (to classify the information). You take something and ordnen it into (ein) the right place."},
{type:"tip",title:"Indefinitpronomen: Das volle Spektrum",text:"German has many indefinite pronouns for formal and academic contexts.\n\nFrom vague to emphatic:\n'irgendein' (some, any) = most vague\n'manch ein' (many a) = literary\n'jeder' (every) = standard\n's\u00e4mtliche' (all, every single) = emphatic\n'jegliche' (any whatsoever) = very formal\n'jedweder' (every last one) = almost legal\n\nFor variety:\n'allerhand' and 'allerlei' both mean 'all sorts of.'\n\nIn B2 writing, using a range of indefinite pronouns signals language competence.\n'Alle Studenten' is A2.\n'S\u00e4mtliche Studierende' is B2.",deepDive:{title:"Indefinite pronouns: declension and style",text:"S\u00e4mtliche, jegliche, and jedweder decline like regular adjectives. They take the same endings as 'alle' or 'jede' depending on the article context.\n\nWithout article (strong declension):\ns\u00e4mtliche Aufgaben (all tasks)\njeglicher Kontakt (any contact whatsoever)\n\n'Allerhand' and 'allerlei' are special: they do NOT decline. They stay unchanged regardless of case: 'allerhand Probleme', 'mit allerhand Tricks.'\n\n'Manch ein' declines like 'ein': 'manch einem' (dative), 'manch einen' (accusative).\n\nIn formal writing, varying your indefinite pronouns signals B2+ competence."}},
{type:"mc",q:"Was ist die formellste Art, 'alle Aufgaben' zu sagen?",opts:["alle Aufgaben (gew\u00f6hnlich)","jede einzelne Aufgabe","irgendwelche Aufgaben (beliebige)","s\u00e4mtliche Aufgaben"],ans:"s\u00e4mtliche Aufgaben",hint:"The emphatic, formal word meaning 'every single one without exception.'",sSrc:"What is the most formal way to say 'all tasks'?"},
{type:"fb",s:"{1} Hilfsmittel sind w\u00e4hrend der Pr\u00fcfung verboten.",a:["Jegliche"],opts:["Jegliche","Alle","Manche","Irgendwelche"],hint:"The strongest, most formal word for 'any whatsoever.' Used in rules and regulations.",sSrc:"Any aids whatsoever are forbidden during the exam."},
{type:"mc",q:"Globalverstehen bedeutet...",opts:["jedes einzelne Detail vollständig verstehen","das Thema und die Hauptidee erfassen","die Grammatik im Text vollständig verstehen","den gesamten Wortschatz des Textes verstehen"],ans:"das Thema und die Hauptidee erfassen",hint:"Global = the big picture. What is the text about in general?",sSrc:"Global comprehension means..."},
{type:"match",pairs:[{trg:"Globalverstehen",src:"gist comprehension"},{trg:"Detailverstehen",src:"detailed comprehension"},{trg:"Hauptaussage",src:"main message"},{trg:"Schl\u00fcsselwort",src:"keyword"},{trg:"erschlie\u00dfen",src:"to infer/deduce"}]},
{type:"drag_fill",s:"{1} du die Schl\u00fcsselw\u00f6rter markierst, kannst du die Hauptaussage schneller {2}.",blanks:{"1":"Indem","2":"erkennen"},pool:["Indem","Weil","erkennen","erschlie\u00dfen","markieren","lesen"],hint:"Two gaps: a manner clause connector showing HOW you find the answer faster, and a verb meaning to identify or perceive the main message.",sSrc:"By marking the keywords, you can recognize the main message faster."},
{type:"fb",s:"Wenn ein Wort unbekannt ist, kann man seine Bedeutung aus dem Kontext {1}.",a:["erschlie\u00dfen"],opts:["erkennen","markieren","erschlie\u00dfen","sortieren"],hint:"Deriving meaning from context. The verb that describes 'unlocking' the meaning.",sSrc:"When a word is unknown, you can infer its meaning from context."},
{type:"mc",q:"Welcher Satz benutzt SOWOHL einen Modalsatz ALS AUCH ein Indefinitpronomen?",opts:["Weil s\u00e4mtliche Texte schwierig sind, brauche ich deutlich mehr Zeit.","Obwohl jeder einzelne Text anders ist, gibt es erkennbare Muster.","Wenn manche Aufgaben leicht sind, l\u00f6se ich den Rest leichter.","Indem man s\u00e4mtliche Texte durchliest, versteht man das Thema."],ans:"Indem man s\u00e4mtliche Texte durchliest, versteht man das Thema.",hint:"The correct sentence must contain both a clause answering HOW AND a formal emphatic word for totality. Check each option for both features.",sSrc:"Which sentence uses BOTH a manner clause AND an indefinite pronoun?"},
{type:"mc",q:"Was bedeutet 'der Absatz'?",opts:["paragraph","all sorts of, various","heading, title","to classify, to categorize"],ans:"paragraph",hint:"A text block separated by spacing. Also means 'heel (of shoe)' or 'sales volume'."}
]},
{id:"deu_r35l5",title:"Doch, halt, eben",icon:"\uD83D\uDDE3\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Doch, halt, eben",desc:"The small words that cannot be translated. Modal particles give German its emotional texture. You will also learn exam vocabulary for listening and speaking.",goals:["Discover modal particles: doch, halt, eben, ja, mal, schon, wohl","Learn exam vocabulary for listening comprehension and speaking","Recognize speaker intentions and nuance"]},
{type:"teach",trg:"der Hoerabschnitt",src:"listening passage",pos:"noun",gender:"m",note:"Hoer (listening) + Abschnitt (section). The Hoerverstehen\nhas multiple Hoerabschnitte: monologues, dialogues, radio segments.",example:"A: Wie viele Hoerabschnitte gibt es?\nB: Vier Hoerabschnitte.\nA: Wird jeder Hoerabschnitt zweimal gespielt?\nB: Ja, bei B2 hoert man alles zweimal.",exampleSrc:"A: How many listening passages are there?\nB: Four listening passages.\nA: Is each listening passage played twice?\nB: Yes, at B2 you hear everything twice.",funFact:"Hoer (listening) + Abschnitt (section). A listening passage. The Hoerverstehen has multiple Hoerabschnitte: monologues, dialogues, radio segments. Each one plays twice at B2 level."},
{type:"teach",trg:"die Redeabsicht",src:"speaker intention",pos:"noun",gender:"f",note:"Rede (speech) + Absicht (intention). What does the speaker\nWANT? To inform, persuade, warn, complain?",example:"A: Was ist die Redeabsicht hier?\nB: Der Sprecher will überzeugen.\nA: Und in diesem Hoerabschnitt?\nB: Hier will er warnen.",exampleSrc:"A: What is the speaker intention here?\nB: The speaker wants to persuade.\nA: And in this listening passage?\nB: Here he wants to warn.",funFact:"Rede (speech) + Absicht (intention). What does the speaker WANT? To inform, persuade, warn, complain? Recognizing Redeabsicht is a B2 listening skill. Words are actions with intentions."},
{type:"teach",trg:"die Sprachhandlung",src:"speech act",pos:"noun",gender:"f",note:"Sprache (language) + Handlung (action). Requesting, refusing,\napologizing: each is a Sprachhandlung. Language does things.",example:"A: Was ist eine Sprachhandlung?\nB: Eine Handlung durch Sprache.\nA: Zum Beispiel?\nB: Bitten, ablehnen, sich entschuldigen.",exampleSrc:"A: What is a speech act?\nB: An action through language.\nA: For example?\nB: Requesting, refusing, apologizing.",funFact:"Sprache (language) + Handlung (action). A speech act. Requesting, refusing, apologizing, suggesting: each is a Sprachhandlung. Language does things. Words are actions."},
{type:"teach",trg:"das Sprachniveau",src:"language level",pos:"noun",gender:"n",note:"Sprache + Niveau (level, from French). A1 to C2.\n'Welches Sprachniveau haben Sie?' Neuter because Niveau is neuter.",example:"A: Welches Sprachniveau haben Sie?\nB: Ich bin auf B2-Niveau.\nA: Sehr gut. Das ist fortgeschritten.\nB: Danke, ich lerne seit zwei Jahren.",exampleSrc:"A: What language level do you have?\nB: I am at B2 level.\nA: Very good. That is advanced.\nB: Thank you, I have been learning for two years.",funFact:"Sprache + Niveau (level, from French). A1 to C2. 'Welches Sprachniveau haben Sie?' is the standard question. Neuter because Niveau is neuter. B2 is the fortgeschritten level."},
{type:"fb",s:"Die {1} des Sprechers erkennen: will er informieren, warnen oder \u00fcberzeugen?",a:["Redeabsicht"],opts:["Redeabsicht","Sprachhandlung","Paraphrase","Notiz"],hint:"The speaker's intention. Rede (speech) + Absicht (intention). What the speaker WANTS to achieve with their words.",sSrc:"Recognizing the speaker's intention: does he want to inform, warn, or persuade?"},
{type:"teach",trg:"das Textverständnis",src:"text comprehension",pos:"noun",gender:"n",note:"Text + Verständnis (understanding). Not whether you know\nevery word, but whether you UNDERSTAND the text.",example:"A: Wie ist dein Textverständnis?\nB: Bei kurzen Texten gut.\nA: Und bei langen Texten?\nB: Da muss ich langsamer lesen.",exampleSrc:"A: How is your text comprehension?\nB: Good with short texts.\nA: And with long texts?\nB: I have to read more slowly there.",funFact:"Text + Verständnis (understanding/comprehension). What the exam really tests: not whether you know every word, but whether you UNDERSTAND the text. The big picture matters."},
{type:"fb",s:"Welches {1} haben Sie? Ich bin auf fortgeschrittenem Niveau.",a:["Sprachniveau"],opts:["Wortfeld","Sprachniveau","Textverst\u00e4ndnis","H\u00f6rabschnitt"],hint:"Sprache (language) + Niveau (level, from French). The standard question about someone's language proficiency level.",sSrc:"What language level do you have? I am at an advanced level."},
{type:"teach",trg:"das Wortfeld",src:"word field, semantic group",pos:"noun",gender:"n",note:"Wort (word) + Feld (field). A semantic group of related words.\nOrganizing vocabulary into Wortfelder helps memory.",example:"A: Was gehört zum Wortfeld Prüfung?\nB: Bestehen, Aufgabe, Bewertung.\nA: Und zum Wortfeld Kochen?\nB: Rezept, Zutat, Herd.",exampleSrc:"A: What belongs to the word field exam?\nB: Passing, task, assessment.\nA: And to the word field cooking?\nB: Recipe, ingredient, stove.",funFact:"Wort (word) + Feld (field). A word field, a semantic group. Organizing vocabulary into Wortfelder helps memory and retrieval. 'Wortfeld Prüfung' includes all words related to exams."},
{type:"teach",trg:"die Notiz",src:"note",pos:"noun",gender:"f",note:"From Latin 'notitia.' 'Notizen machen' (to take notes) is\nessential during the Hoerverstehen. Quick notes, not full sentences.",example:"A: Machst du Notizen?\nB: Ja, immer beim Hoerverstehen.\nA: In ganzen Saetzen?\nB: Nein, nur Stichwörter.",exampleSrc:"A: Do you take notes?\nB: Yes, always during listening comprehension.\nA: In full sentences?\nB: No, only keywords.",funFact:"'Notizen machen' (to take notes) is essential during the Hoerverstehen. Quick notes, not full sentences. Speed beats perfection. The word traces to Latin 'notitia' (note/knowledge)."},
{type:"teach",trg:"das Stichwort",src:"keyword, cue word",pos:"noun",gender:"n",note:"Stich (stitch/prick) + Wort. A keyword or bullet point.\n'In Stichwörtern notieren' is the exam technique.",example:"A: Notiere in Stichwörtern.\nB: Also keine ganzen Saetze?\nA: Nein, nur die wichtigsten Stichwörter.\nB: Das spart Zeit.",exampleSrc:"A: Note down in keywords.\nB: So no full sentences?\nA: No, only the most important keywords.\nB: That saves time.",funFact:"Stich (stitch/prick) + Wort. A keyword, a bullet point, a cue word. 'In Stichwörtern notieren' (to note down in keywords). Capture Stichwörter, not sentences. Speed is everything."},
{type:"teach",trg:"die Paraphrase",src:"paraphrase",pos:"noun",gender:"f",note:"From Greek 'paraphrasis.' A restatement in different words.\nThe noun form of 'paraphrasieren.'",example:"A: Was ist eine Paraphrase?\nB: Eine Umformulierung.\nA: Warum ist das wichtig?\nB: Man zeigt, dass man den Text versteht.",exampleSrc:"A: What is a paraphrase?\nB: A reformulation.\nA: Why is that important?\nB: You show that you understand the text.",funFact:"The noun form of 'paraphrasieren.' A good Paraphrase keeps the meaning but changes every word. Essential for B2 writing and showing vocabulary mastery. Greek root: 'paraphrasis' (restatement)."},
{type:"teach",trg:"notieren",src:"to note down, to jot",pos:"verb",gender:null,note:"From Latin 'notare' (to mark/note). More formal than\n'aufschreiben.' The exam skill of capturing information quickly.",example:"A: Bitte notieren Sie die wichtigsten Punkte.\nB: Soll ich alles notieren?\nA: Nur die Hauptaussagen notieren.\nB: Verstanden, ich notiere nur das Wichtigste.",exampleSrc:"A: Please note down the most important points.\nB: Should I note down everything?\nA: Only note down the main messages.\nB: Understood, I will only note the most important things.",funFact:"More formal than 'aufschreiben,' notieren means to jot down quickly. 'Bitte notieren Sie die wichtigsten Punkte.' The exam skill of capturing information fast. Latin root: 'notare' (to mark)."},
{type:"match",pairs:[{trg:"die Notiz",src:"note"},{trg:"das Stichwort",src:"keyword, cue word"},{trg:"die Paraphrase",src:"paraphrase"},{trg:"notieren",src:"to note down, to jot"}]},
{type:"teach",trg:"wiedergeben",src:"to reproduce, to relay",pos:"verb",gender:null,note:"Wieder (again) + geben (to give). To relay content in your\nown words. Separable: 'Den Inhalt wiedergeben.'",example:"A: Kannst du den Inhalt wiedergeben?\nB: Der Text handelt von Umweltschutz.\nA: Gut. Gib die Hauptaussage wieder.\nB: Der Autor fordert mehr Recycling.",exampleSrc:"A: Can you relay the content?\nB: The text is about environmental protection.\nA: Good. Relay the main message.\nB: The author demands more recycling.",funFact:"Wieder (again) + geben (to give). To reproduce, to render, to relay. Separable. You give the content back (wieder) in your own words. A core exam skill."},
{type:"teach",trg:"zuordnen",src:"to assign, to match",pos:"verb",gender:null,note:"Zu (to) + ordnen (to order). To classify or categorize.\nSeparable: 'Die Überschriften den Texten zuordnen.'",example:"A: Ordnen Sie die Überschriften zu.\nB: Text A gehört zu Überschrift 3.\nA: Und Text B?\nB: Den ordne ich Überschrift 1 zu.",exampleSrc:"A: Assign the headings.\nB: Text A belongs to heading 3.\nA: And text B?\nB: I assign that to heading 1.",funFact:"Zu (to) + ordnen (to order). To assign, to match, to categorize. Separable. 'Die Überschriften den Texten zuordnen' (assign headings to texts). A classic exam task type."},
{type:"mc",q:"Was ist der Unterschied zwischen Notiz und Stichwort?",opts:["Notiz und Stichwort bedeuten genau dasselbe","Eine Notiz ist formell, ein Stichwort ist informell","Eine Notiz kann ein Satz sein, ein Stichwort ist ein einzelnes Wort","Stichwort ist formeller als Notiz"],ans:"Eine Notiz kann ein Satz sein, ein Stichwort ist ein einzelnes Wort",hint:"One type can be full sentences; the other uses only isolated words or fragments for speed. Exams favour the faster style."},
{type:"fb",s:"Hoeren Sie den {1} und beantworten Sie die Fragen.",a:["Hoerabschnitt"],opts:["Hoerabschnitt","Aufgabentyp","Lückentext","Maßstab"],hint:"A section of audio you listen to during an exam. Hoer (listening) + Abschnitt (section/passage).",sSrc:"Listen to the listening passage and answer the questions."},
{type:"mc",q:"Geben Sie den Inhalt des Textes in eigenen Worten {blank}.",opts:["wieder","zu","ab","an"],ans:"wieder",hint:"Think of the separable verb for 'to reproduce' or 'to relay.' Its prefix appears at the end of the clause."}
]},
{id:"deu_r35l5b",title:"Doch, halt, eben (Teil 2)",icon:"\uD83D\uDDE3\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Doch, halt, eben (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"entschlüsseln",src:"to decode, to decipher",pos:"verb",gender:null,note:"Ent- (un-) + schlüsseln (from Schlüssel, key). To unlock\nmeaning. You use Schlüsselwörter to entschlüsseln the text.",example:"A: Wie entschlüsselt man einen schwierigen Text?\nB: Zuerst die Schlüsselwörter finden.\nA: Und dann?\nB: Dann die Bedeutung aus dem Kontext entschlüsseln.",exampleSrc:"A: How do you decode a difficult text?\nB: First find the keywords.\nA: And then?\nB: Then decode the meaning from context.",funFact:"Ent- (un-) + schlüsseln (from Schlüssel, key). To decode, to decipher. Literally to un-lock. You use your Schlüsselwörter to entschlüsseln the text. Not separable."},
{type:"teach",trg:"priorisieren",src:"to prioritize",pos:"verb",gender:null,note:"From Latin 'prior' (earlier/more important). A study and\nexam skill. Not everything is equally important.",example:"A: Wie priorisierst du deine Aufgaben?\nB: Ich mache die schwierigen zuerst.\nA: Priorisieren ist wichtig.\nB: Ja, besonders in der Prüfung.",exampleSrc:"A: How do you prioritize your tasks?\nB: I do the difficult ones first.\nA: Prioritizing is important.\nB: Yes, especially in the exam.",funFact:"Not everything is equally important. Priorisieren means choosing what matters most. 'Aufgaben priorisieren' (to prioritize tasks) is a key exam strategy. Latin root: 'prior' (earlier/more important)."},
{type:"teach",trg:"mündlich",src:"oral, spoken",pos:"adj",gender:null,note:"Mund (mouth) + -lich. The opposite of 'schriftlich.'\nThe Sprechen section is the mündliche Prüfung.",example:"A: Ist die Prüfung schriftlich oder mündlich?\nB: Beides. Schriftlich und mündlich.\nA: Was ist schwerer?\nB: Für mich ist die mündliche Prüfung schwerer.",exampleSrc:"A: Is the exam written or oral?\nB: Both. Written and oral.\nA: What is harder?\nB: For me the oral exam is harder.",funFact:"Mund (mouth) + -lich. Oral, spoken. 'Mündliche Prüfung' (oral exam). The opposite of 'schriftlich.' The Sprechen section is the mündliche Prüfung. Speaking out loud with your Mund."},
{type:"teach",trg:"kurzgefasst",src:"concise, brief",pos:"adj",gender:null,note:"Kurz (short) + gefasst (composed/grasped). The art of saying\nmuch with few words. 'Kurzgefasst bedeutet das...'",example:"A: Erkläre das kurzgefasst.\nB: Kurzgefasst: Modalpartikeln zeigen Gefühle.\nA: Das war wirklich kurzgefasst.\nB: Kurz und treffend.",exampleSrc:"A: Explain that briefly.\nB: In brief: modal particles show emotions.\nA: That was really concise.\nB: Short and apt.",funFact:"Kurz (short) + gefasst (composed/grasped). Concise, brief, succinct. 'Kurzgefasst bedeutet das...' (In brief, that means...). The art of saying much with few words."},
{type:"teach",trg:"treffend",src:"apt, fitting, well-chosen",pos:"adj",gender:null,note:"From 'treffen' (to hit/meet). When your word choice hits\nthe mark perfectly. The highest compliment for language use.",example:"A: Das war ein treffender Ausdruck.\nB: Danke, ich habe lange überlegt.\nA: Treffende Formulierungen bekommt man mit Übung.\nB: Ja, Übung macht den Meister.",exampleSrc:"A: That was an apt expression.\nB: Thank you, I thought about it for a long time.\nA: You get apt formulations with practice.\nB: Yes, practice makes perfect.",funFact:"When your word choice hits the mark perfectly, that is treffend. 'Ein treffender Ausdruck' (an apt expression). The highest compliment for language use. The root verb 'treffen' means to hit."},
{type:"tip",title:"Modalpartikeln: Die Seele des gesprochenen Deutsch",text:"Modal particles are small words (doch, halt, eben, ja, mal, schon, wohl) that express emotion and attitude. They cannot be translated directly. They change the FEELING, not the meaning.\n\n'Komm!' vs. 'Komm mal!' (a little softer)\n'Das ist schwer.' vs. 'Das ist halt schwer.' (acceptance)\n\ndoch = contradiction or emphasis: 'Das stimmt doch!'\nhalt/eben = acceptance of reality: 'Es ist halt so.'\nja = shared knowledge: 'Das wissen wir ja.'\nmal = softener: 'Schau mal.'\nschon = concession: 'Das stimmt schon, aber...'\nwohl = assumption: 'Er ist wohl krank.'\n\nNative speakers use 5-10 particles per conversation.",deepDive:{title:"Why modal particles are hard to learn",text:"Modal particles have no fixed translation. 'Doch' alone has over ten different nuances.\n\nThe key: do not translate them, FEEL them.\n\nTip: Listen to German podcasts and pay attention to the small words between the big ones. Over time you develop an instinct for them.\n\n'Halt' and 'eben' are nearly identical. 'Halt' sounds slightly southern German, 'eben' slightly northern German. Both mean: that is just how it is."}},
{type:"mc",q:"Jemand sagt: 'Das war doch gar nicht so schwer.' Was macht 'doch' hier?",opts:["Es verneint und bestätigt das Gegenteil: Es war sehr schwer.","Es stellt eine indirekte Frage an den Zuhörer.","Es ist ein Füllwort ohne grammatische Funktion.","Es betont und widerspricht: Es war NICHT so schwer!"],ans:"Es betont und widerspricht: Es war NICHT so schwer!",hint:"'Doch' expresses contradiction. It says: contrary to what you might think..."},
{type:"fb",s:"Es ist {1} so. Man kann nichts ändern.",a:["halt"],opts:["halt","doch","ja","wohl"],hint:"A modal particle for quiet resignation. Not a strong disagreement, not excitement. Just quiet acceptance of an unchangeable fact.",sSrc:"It is just like that. You cannot change anything."},
{type:"drag_fill",s:"{1} man Modalpartikeln benutzt, klingt man {2} {3} natürlicher.",blanks:{"1":"Indem","2":"halt","3":"einfach"},pool:["Indem","halt","einfach","Weil","doch","schnell"],hint:"Three gaps: a manner clause connector, then a particle of resigned acceptance, then a particle meaning 'simply.' Together they show how particles make speech feel natural.",sSrc:"By using modal particles, you just simply sound more natural."},
{type:"mc",q:"Welcher Satz kombiniert einen Modalsatz, ein Indefinitpronomen UND eine Modalpartikel?",opts:["Weil sämtliche Texte schwer sind, ist das halt leider so einmal.","Indem man sämtliche Texte liest, versteht man das Thema halt besser.","Obwohl jeder Text einen anderen Aufbau hat, schafft man es dann schon.","Wenn manche Prüfungsaufgaben leichter sind, läuft der Rest halt doch."],ans:"Indem man sämtliche Texte liest, versteht man das Thema halt besser.",hint:"The correct sentence combines all three layers: a clause connector answering HOW, a formal emphatic pronoun for totality, and a particle of acceptance. Check each option."},
{type:"mc",q:"Was bedeutet 'entschlüsseln'?",opts:["oral, spoken","to decode, to decipher","text comprehension","to prioritize"],ans:"to decode, to decipher",hint:"ent- (un-) + Schlüssel (key). To unlock a coded message. The reverse of encryption."},
{type:"fb",s:"{1} ist wichtig.",a:["priorisieren"],opts:["priorisieren","das Wortfeld","die Notiz","zuordnen"],hint:"From Priorität (priority). The -ieren suffix makes it a verb: to rank by importance.",sSrc:"Prioritizing is important."},
{type:"mc",q:"Was bedeutet 'kurzgefasst'?",opts:["concise, brief","to note down, to jot","to decode, to decipher","keyword, cue word"],ans:"concise, brief",hint:"kurz (short) + gefasst (composed/drafted). Composed in short form. Getting to the point."},
{type:"fb",s:"Das war ein {1}er Ausdruck.",a:["treffend"],opts:["treffend","das Textverständnis","kurzgefasst","priorisieren"],hint:"From treffen (to hit/meet). Hitting the mark exactly. An expression that fits perfectly.",sSrc:"That was an apt expression."}
]},
{id:"deu_r35l6",title:"Nachtspaziergang",icon:"\uD83C\uDF03",xp:15,board:true,steps:[
{type:"intro",title:"Nachtspaziergang",desc:"The exam is over. Verumius walks through his Berlin at night. Every street corner is a vocabulary lesson. Every sign a test he has already passed.",goals:["Follow Verumius on his night walk through Berlin","Review all grammar constructs in mixed exercises","Connect language learning with lived experience"]},
{type:"teach",trg:"das Prüfungsergebnis",src:"exam result",pos:"noun",gender:"n",note:"Prüfung + Ergebnis (result). The email you wait for.\n'Bestanden' oder 'Nicht bestanden.' 60% minimum at B2.",example:"A: Wann kommt das Prüfungsergebnis?\nB: In drei bis fünf Tagen.\nA: Bekommt man das per Email?\nB: Ja, das Prüfungsergebnis kommt digital.",exampleSrc:"A: When does the exam result come?\nB: In three to five days.\nA: Do you get it by email?\nB: Yes, the exam result comes digitally.",funFact:"Prüfung + Ergebnis (result). An exam result. The email you wait for. 'Bestanden' (passed) or 'Nicht bestanden.' At B2 level, you need 60% overall with minimums in each section."},
{type:"teach",trg:"der Themenvorschlag",src:"topic suggestion",pos:"noun",gender:"m",note:"Thema (topic) + Vorschlag (suggestion). The Schreiben section\ngives you a Themenvorschlag to argue for or against.",example:"A: Welchen Themenvorschlag hast du gewaehlt?\nB: Den über digitale Medien in der Schule.\nA: War der Themenvorschlag schwer?\nB: Nein, ich hatte gute Argumente.",exampleSrc:"A: Which topic suggestion did you choose?\nB: The one about digital media in school.\nA: Was the topic suggestion difficult?\nB: No, I had good arguments.",funFact:"Thema (topic) + Vorschlag (suggestion). A topic suggestion. The Schreiben section gives you a Themenvorschlag that you must argue for or against. Choose wisely."},
{type:"teach",trg:"die Beispielantwort",src:"example answer",pos:"noun",gender:"f",note:"Beispiel (example) + Antwort. Practice exams include\nBeispielantworten to show what good responses look like.",example:"A: Gibt es eine Beispielantwort?\nB: Ja, im Übungsbuch.\nA: Hilft die Beispielantwort?\nB: Sehr. Man sieht, was erwartet wird.",exampleSrc:"A: Is there an example answer?\nB: Yes, in the practice book.\nA: Does the example answer help?\nB: Very much. You see what is expected.",funFact:"Beispiel (example) + Antwort. An example answer. Practice exams include Beispielantworten to show what good responses look like. Study the model, then write your own."},
{type:"mc",q:"Was ist eine Beispielantwort?",opts:["Eine Antwort, die zeigt, wie eine gute Antwort aussieht","Eine falsche Antwort zum Vergleich","Die erste Antwort in einer Pr\u00fcfung","Eine m\u00fcndliche Antwort im Gespr\u00e4ch"],ans:"Eine Antwort, die zeigt, wie eine gute Antwort aussieht",hint:"A model response included in practice materials. It shows test-takers what a good answer looks like."},
{type:"teach",trg:"die Nacherzählung",src:"retelling, narrative reproduction",pos:"noun",gender:"f",note:"Nach (after) + Erzählung (narration). You hear a story,\nthen produce a Nacherzählung in your own words.",example:"A: Schreiben Sie eine Nacherzählung.\nB: In eigenen Worten?\nA: Ja, eine Nacherzählung ist keine wörtliche Kopie.\nB: Verstanden, ich gebe den Inhalt wieder.",exampleSrc:"A: Write a retelling.\nB: In my own words?\nA: Yes, a retelling is not a word-for-word copy.\nB: Understood, I will relay the content.",funFact:"Nach (after) + Erzählung (narration). A retelling, a narrative reproduction. The noun form of 'nacherzählen.' You hear a story, then produce a Nacherzählung."},
{type:"teach",trg:"das Korrekturlesen",src:"proofreading",pos:"noun",gender:"n",note:"Korrektur (correction) + Lesen (reading). The final five\nminutes of the writing exam. Catch errors. Save grades.",example:"A: Hast du Zeit für Korrekturlesen?\nB: Immer. Korrekturlesen ist Pflicht.\nA: Was soll man beim Korrekturlesen beachten?\nB: Grammatik, Rechtschreibung, Satzbau.",exampleSrc:"A: Do you have time for proofreading?\nB: Always. Proofreading is mandatory.\nA: What should you look for when proofreading?\nB: Grammar, spelling, sentence structure.",funFact:"Korrektur (correction) + Lesen (reading). Proofreading. The final five minutes of the writing exam: read everything again. Catch errors. Korrekturlesen saves grades."},
{type:"teach",trg:"das Zeitmanagement",src:"time management",pos:"noun",gender:"n",note:"Zeit (time) + Management. At B2 level, Zeitmanagement\ndecides pass or fail. 75 minutes for Schreiben: plan, write, check.",example:"A: Zeitmanagement ist entscheidend.\nB: Ja, ohne gutes Zeitmanagement schafft man es nicht.\nA: Wie teilst du die Zeit ein?\nB: Zehn Minuten planen, fünfzig schreiben, fünfzehn prüfen.",exampleSrc:"A: Time management is crucial.\nB: Yes, without good time management you will not make it.\nA: How do you divide the time?\nB: Ten minutes planning, fifty writing, fifteen checking.",funFact:"Zeit (time) + Management. At B2 level, Zeitmanagement decides pass or fail. 75 minutes for Schreiben means: 10 for planning, 50 for writing, 15 for Korrekturlesen."},
{type:"teach",trg:"die Zuordnung",src:"matching task, assignment",pos:"noun",gender:"f",note:"Zu (to) + Ordnung (order). Match headings to paragraphs,\nspeakers to opinions. A common Aufgabentyp.",example:"A: Die nächsste Aufgabe ist eine Zuordnung.\nB: Was muss ich zuordnen?\nA: Überschriften zu Textabschnitten.\nB: Zuordnungsaufgaben finde ich leicht.",exampleSrc:"A: The next task is a matching exercise.\nB: What do I have to match?\nA: Headings to text sections.\nB: I find matching tasks easy.",funFact:"Zu (to) + Ordnung (order). An assignment, a matching task. 'Zuordnungsaufgabe' (matching task) is a common exam format. Match headings to paragraphs, speakers to opinions."},
{type:"teach",trg:"das Diagramm",src:"diagram, chart",pos:"noun",gender:"n",note:"From Greek 'diagramma.' B2 writing sometimes requires\ndescribing a Diagramm: bar charts, pie charts, line graphs.",example:"A: Beschreiben Sie das Diagramm.\nB: Das Diagramm zeigt den Anstieg der Temperaturen.\nA: Welche Art von Diagramm ist das?\nB: Ein Balkendiagramm.",exampleSrc:"A: Describe the diagram.\nB: The diagram shows the rise in temperatures.\nA: What kind of diagram is that?\nB: A bar chart.",funFact:"B2 writing sometimes requires describing a Diagramm: bar charts, pie charts, line graphs. Data plus language equals Diagramm description. The word goes back to Greek 'diagramma' (figure/drawing)."},
{type:"fb",s:"Das {1} ist entscheidend: 10 Minuten planen, 50 schreiben, 15 pr\u00fcfen.",a:["Zeitmanagement"],opts:["Zeitmanagement","Korrekturlesen","Pr\u00fcfungsergebnis","Themenvorschlag"],hint:"Zeit (time) + Management. How you divide the 75 minutes for the writing section decides pass or fail.",sSrc:"Time management is crucial: 10 minutes planning, 50 writing, 15 checking."}
]},
{id:"deu_r35l6b",title:"Nachtspaziergang (Teil 2)",icon:"\uD83C\uDF03",xp:15,board:true,steps:[
{type:"intro",title:"Nachtspaziergang (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"durcharbeiten",src:"to work through, to study thoroughly",pos:"verb",gender:null,note:"Durch (through) + arbeiten (to work). Thorough, systematic\nwork from beginning to end. Separable. No skipping.",example:"A: Hast du das Material durchgearbeitet?\nB: Ja, von Anfang bis Ende.\nA: Alles durcharbeiten dauert lange.\nB: Aber es lohnt sich.",exampleSrc:"A: Did you work through the material?\nB: Yes, from beginning to end.\nA: Working through everything takes a long time.\nB: But it is worth it.",funFact:"Durch (through) + arbeiten (to work). To work through, to study thoroughly. Separable. Thorough, systematic work from beginning to end. No skipping."},
{type:"teach",trg:"untergliedern",src:"to subdivide",pos:"verb",gender:null,note:"Unter (sub-) + gliedern (to structure). Not separable.\nFiner structure within structure. A subsection within a section.",example:"A: Kann man den Hauptteil untergliedern?\nB: Ja, in drei Abschnitte.\nA: Wie untergliedert man am besten?\nB: Nach Argumenten: Pro, Contra, Fazit.",exampleSrc:"A: Can you subdivide the main body?\nB: Yes, into three sections.\nA: How do you best subdivide?\nB: By arguments: pro, contra, conclusion.",funFact:"Unter (sub-) + gliedern (to structure). To subdivide. Not separable. Finer structure within structure. A subsection within a section. 'Den Hauptteil in Abschnitte untergliedern.'"},
{type:"teach",trg:"genügen",src:"to suffice, to be enough",pos:"verb",gender:null,note:"From 'genug' (enough). Formal version of 'Das reicht.'\n'Den Anforderungen genügen' (to meet the requirements).",example:"A: Genuegt diese Antwort?\nB: Nein, sie ist zu kurz.\nA: Was würde genügen?\nB: Zwei Argumente mit Beispielen genügen.",exampleSrc:"A: Does this answer suffice?\nB: No, it is too short.\nA: What would suffice?\nB: Two arguments with examples would suffice.",funFact:"'Das genuegt' is the formal version of 'Das reicht' (That is enough). 'Den Anforderungen genuegen' means to meet the requirements. The root is simply 'genug' (enough)."},
{type:"teach",trg:"sprachlich",src:"linguistic, language-related",pos:"adj",gender:null,note:"Sprache + -lich. What the exam measures: your ability to\nuse language well. 'Sprachliche Kompetenz.'",example:"A: Wie ist seine sprachliche Kompetenz?\nB: Sehr gut für B2-Niveau.\nA: Sprachliche Fehler kosten Punkte.\nB: Deshalb ist Korrekturlesen wichtig.",exampleSrc:"A: How is his linguistic competence?\nB: Very good for B2 level.\nA: Linguistic errors cost points.\nB: That is why proofreading is important.",funFact:"Sprache + -lich. Linguistic, language-related. 'Sprachliche Kompetenz' (linguistic competence). What the exam measures. Your ability to use language well."},
{type:"teach",trg:"textbezogen",src:"text-based, text-related",pos:"adj",gender:null,note:"Text + bezogen (related to). The exam wants evidence FROM\nthe text. Do not answer from imagination.",example:"A: Ihre Antwort muss textbezogen sein.\nB: Also direkt aus dem Text?\nA: Ja, textbezogene Antworten mit Textstellen.\nB: Ich zitiere dann den zweiten Absatz.",exampleSrc:"A: Your answer must be text-based.\nB: So directly from the text?\nA: Yes, text-based answers with text references.\nB: I will then quote the second paragraph.",funFact:"Text + bezogen (related to). Text-related, based on the text. 'Textbezogene Antworten' (text-based answers). The exam wants evidence FROM the text. Do not answer from imagination."},
{type:"match",pairs:[{trg:"untergliedern",src:"to subdivide"},{trg:"genügen",src:"to suffice, to be enough"},{trg:"sprachlich",src:"linguistic, language-related"},{trg:"textbezogen",src:"text-based, text-related"}]},
{type:"teach",trg:"stichpunktartig",src:"in bullet-point form",pos:"adj",gender:null,note:"Stichpunkt (bullet point) + -artig (like/in the manner of).\nNotes that look like bullet points. Fast and structured.",example:"A: Notieren Sie stichpunktartig.\nB: Also keine ganzen Saetze?\nA: Nein, stichpunktartig reicht.\nB: Das spart viel Zeit.",exampleSrc:"A: Note down in bullet-point form.\nB: So no full sentences?\nA: No, bullet-point form is enough.\nB: That saves a lot of time.",funFact:"Stichpunkt (bullet point) + -artig (like/in the manner of). In bullet-point form. 'Stichpunktartig notieren.' The -artig suffix means 'in the manner of.' Notes that look like bullet points."},
{type:"teach",trg:"übersichtlich",src:"clear, well-organized",pos:"adj",gender:null,note:"Übersicht (overview) + -lich. Everything in its place,\neverything visible at a glance. The highest compliment for structure.",example:"A: Dein Text ist sehr übersichtlich.\nB: Danke, ich habe gut gegliedert.\nA: Übersichtliche Texte bekommen bessere Noten.\nB: Struktur ist alles.",exampleSrc:"A: Your text is very well-organized.\nB: Thank you, I structured it well.\nA: Well-organized texts get better grades.\nB: Structure is everything.",funFact:"Übersicht (overview) + -lich. Clear, well-organized, easy to survey. 'Ein übersichtliches Layout.' The highest compliment for structure. Everything in its place, everything visible at a glance."},
{type:"mc",q:"Was bedeutet 'stichpunktartig notieren'?",opts:["In ganzen S\u00e4tzen und sehr ausf\u00fchrlich aufschreiben","Den Text w\u00f6rtlich und komplett abschreiben","Nur die \u00dcberschrift aufschreiben und nichts weiter","In Stichw\u00f6rtern und kurzen Punkten notieren"],ans:"In Stichw\u00f6rtern und kurzen Punkten notieren",hint:"Stichpunkt (bullet point) + -artig (in the manner of). Notes that look like bullet points. Fast and structured."},
{type:"teach",trg:"umgangssprachlich",src:"colloquial, informal",pos:"adj",gender:null,note:"Umgangssprache (colloquial language) + -lich. In formal B2\nwriting, avoid umgangssprachliche Ausdrücke.",example:"A: Ist 'cool' umgangssprachlich?\nB: Ja, in der Prüfung besser vermeiden.\nA: Was ist nicht umgangssprachlich?\nB: 'Beeindruckend' statt 'cool.'",exampleSrc:"A: Is 'cool' colloquial?\nB: Yes, better to avoid in the exam.\nA: What is not colloquial?\nB: 'Impressive' instead of 'cool.'",funFact:"Umgangssprache (colloquial language) + -lich. Colloquial, informal. In formal B2 writing, you avoid umgangssprachliche words. But in the Sprechen section, some naturalness is expected."},
{type:"teach",trg:"unvollständig",src:"incomplete",pos:"adj",gender:null,note:"Un- + vollständig (complete). Always double-check:\nis your answer vollständig or unvollständig?",example:"A: Ihre Antwort ist unvollständig.\nB: Was fehlt?\nA: Das zweite Argument fehlt.\nB: Ich ergaenze die unvollständige Antwort.",exampleSrc:"A: Your answer is incomplete.\nB: What is missing?\nA: The second argument is missing.\nB: I will complete the incomplete answer.",funFact:"Un- + vollständig (complete). Incomplete. 'Unvollständige Antworten erhalten weniger Punkte.' The un- prefix negates completeness. Always double-check: is your answer vollständig?"},
{type:"mc",q:"Ein Kandidat sagt: 'Zeitmanagement ist halt das Wichtigste bei der Prüfung.' Was drückt 'halt' aus?",opts:["Starke Ablehnung: Das will ich nicht akzeptieren.","Resignierte Akzeptanz: So ist es nun mal.","Eine Frage: Ist das wirklich so?","Begeisterung: Das ist fantastisch!"],ans:"Resignierte Akzeptanz: So ist es nun mal.",hint:"'Halt' expresses: 'That's just how it is.' No discussion, just acceptance of a fact."},
{type:"fb",s:"Er hat die Prüfung bestanden, {1} dass er nervoes war.",a:["ohne"],opts:["ohne","indem","anstatt","dadurch"],hint:"A manner clause connector meaning the accompanying action did NOT happen. He achieved the result while that other thing was absent.",sSrc:"He passed the exam without being nervous."},
{type:"drag_fill",s:"{1} man {2} Übungsaufgaben durcharbeitet, gewöhnt man sich {3} an den Prüfungsstil.",blanks:{"1":"Indem","2":"sämtliche","3":"halt"},pool:["Indem","sämtliche","halt","Weil","jegliche","doch"],hint:"Three constructs combined: a manner clause opener, an emphatic indefinite pronoun for totality, and a particle of quiet acceptance. Together they describe thorough, calm practice.",sSrc:"By working through all practice tasks, you just get used to the exam style."},
{type:"match",pairs:[{trg:"Korrekturlesen",src:"proofreading"},{trg:"Zeitmanagement",src:"time management"},{trg:"Nacherzählung",src:"retelling"},{trg:"übersichtlich",src:"clear/well-organized"},{trg:"textbezogen",src:"text-based"}]},
{type:"mc",q:"Verumius sagt: 'Indem ich durch diese Straßen gehe, gehe ich durch mein ganzes Deutsch.' Das ist ein Modalsatz mit...",opts:["einer wörtlichen Bedeutung: Er übt Deutsch während er durch die Straßen Berlins geht.","einem Grammatikfehler, da 'durch' nicht so verwendet werden kann.","keiner tieferen Bedeutung, denn es ist ein ganz normaler Satz.","einer metaphorischen Bedeutung: durch Straßen gehen = durch sein ganzes Deutsch gehen."],ans:"einer metaphorischen Bedeutung: durch Straßen gehen = durch sein ganzes Deutsch gehen.",hint:"The manner clause describes HOW his walk becomes a journey through everything he has learned."},
{type:"mc",q:"Was bedeutet 'durcharbeiten'?",opts:["to work through, to study thoroughly","time management","example answer","in bullet-point form"],ans:"to work through, to study thoroughly",hint:"durch- (all the way) + arbeiten. To go from start to finish in a text or subject without skipping."},
{type:"fb",s:"Kann man den Hauptteil {1}?",a:["untergliedern"],opts:["stichpunktartig","durcharbeiten","sprachlich","untergliedern"],hint:"unter- (sub-) + gliedern (to structure). To break into smaller subsections.",sSrc:"Can you subdivide the main body?"},
{type:"mc",q:"Was bedeutet 'genügen'?",opts:["exam result","diagram, chart","to suffice, to be enough","topic suggestion"],ans:"to suffice, to be enough",hint:"A formal verb implying a threshold has been met. Often with dative: Das genügt mir (that is satisfactory for me)."},
{type:"fb",s:"Wie ist seine {1}e Kompetenz?",a:["sprachlich"],opts:["sprachlich","das Zeitmanagement","untergliedern","unvollständig"],hint:"From Sprache (language). The -lich suffix: relating to language or linguistic ability.",sSrc:"How is his linguistic competence?"},
{type:"mc",q:"Was bedeutet 'umgangssprachlich'?",opts:["clear, well-organized","linguistic, language-related","colloquial, informal","time management"],ans:"colloquial, informal",hint:"Umgang (interaction/dealing) + Sprache (language) + -lich. The language of everyday interaction."}
]},
{id:"deu_r35l7",title:"Generalprobe",icon:"\uD83C\uDFAF",xp:15,board:true,steps:[
{type:"intro",title:"Generalprobe",desc:"Test everything from Unit 35. Modal clauses, indefinite pronouns, modal particles, formal connectors. Show B2 level in writing, reading, and analysis.",goals:["Test all grammar constructs from Unit 35","Demonstrate B2 level with modal clauses and formal connectors","Combine all three constructs in complex sentences"]},
{type:"teach",trg:"indem",src:"by (doing something)",pos:"conj",gender:null,note:"In + dem (which). The most important Modalsatz connector.\n'Indem ich uebe, lerne ich.' Answers: How do you achieve X?",example:"A: Wie lernst du am besten?\nB: Indem ich jeden Tag uebe.\nA: Indem man liest, verbessert man den Wortschatz.\nB: Stimmt, indem man viel liest.",exampleSrc:"A: How do you learn best?\nB: By practicing every day.\nA: By reading, you improve your vocabulary.\nB: True, by reading a lot.",funFact:"In + dem (which). By (doing something), by means of. The most important Modalsatz connector. Answers: 'How do you achieve X?' 'By doing Y.' Verb goes to the END."},
{type:"teach",trg:"dadurch dass",src:"through the fact that",pos:"conj",gender:null,note:"Dadurch (through that) + dass. More explicit than 'indem.'\nEmphasizes the causal mechanism behind the result.",example:"A: Wie hat er sich verbessert?\nB: Dadurch dass er viel gelesen hat.\nA: Dadurch dass man uebt, wird man sicherer.\nB: Ja, Übung macht den Unterschied.",exampleSrc:"A: How did he improve?\nB: Through the fact that he read a lot.\nA: Through the fact that one practices, one becomes more confident.\nB: Yes, practice makes the difference.",funFact:"Dadurch (through that) + dass. Through the fact that, by the fact that. More explicit than 'indem.' Emphasizes the causal mechanism. The verb goes to the end of the dass-clause."},
{type:"teach",trg:"ohne dass",src:"without (doing)",pos:"conj",gender:null,note:"Ohne (without) + dass. The negative manner clause. Something\nhappened, but the expected action did NOT happen.",example:"A: Er ging, ohne dass er sich verabschiedete.\nB: Das war unhöflich.\nA: Sie bestand, ohne dass sie nervoes wurde.\nB: Beeindruckend.",exampleSrc:"A: He left without saying goodbye.\nB: That was impolite.\nA: She passed without getting nervous.\nB: Impressive.",funFact:"Ohne (without) + dass. Without doing. The negative manner clause. Something happened, but the expected accompanying action did NOT happen. 'Er ging, ohne dass er sich verabschiedete.'"},
{type:"teach",trg:"anstatt dass",src:"instead of (doing)",pos:"conj",gender:null,note:"Anstatt (instead of) + dass. The substitution manner clause.\nWhat someone does INSTEAD of what they should do.",example:"A: Anstatt dass er lernt, spielt er.\nB: Das ist nicht klug.\nA: Anstatt dass sie schreibt, liest sie.\nB: Immerhin liest sie.",exampleSrc:"A: Instead of studying, he plays.\nB: That is not smart.\nA: Instead of writing, she reads.\nB: At least she reads.",funFact:"Anstatt (instead of) + dass. Instead of doing. The substitution manner clause. What someone does INSTEAD of what they should do. Verb goes to the end."},
{type:"fb",s:"Er bestand die Pr\u00fcfung, {1} dass er nervoes wurde.",a:["ohne"],opts:["ohne","indem","anstatt","dadurch"],hint:"He passed without the expected thing happening. The negative manner clause connector.",sSrc:"He passed the exam without getting nervous."},
{type:"teach",trg:"auf diese Weise",src:"in this way, thus",pos:"adv",gender:null,note:"Auf (in) + diese (this) + Weise (way/manner). A formal\nconnector for academic writing. Slightly old-fashioned but elegant.",example:"A: Markieren Sie zuerst die Schlüsselwörter.\nB: Und dann?\nA: Auf diese Weise finden Sie die Antwort schneller.\nB: Auf diese Weise spart man also Zeit.",exampleSrc:"A: First mark the keywords.\nB: And then?\nA: In this way you find the answer faster.\nB: So in this way one saves time.",funFact:"Auf (in) + diese (this) + Weise (way/manner). In this way, thus. A formal connector for academic writing. Slightly old-fashioned but elegant. 'Auf diese Weise verbessern Sie Ihre Note.'"},
{type:"teach",trg:"infolge",src:"as a result of, owing to",pos:"prep",gender:null,note:"In + Folge (consequence). A formal causal preposition.\nTakes Genitiv. 'Infolgedessen' is the adverb form.",example:"A: Infolge der guten Vorbereitung bestand er.\nB: Infolge des schlechten Wetters blieb sie zu Hause.\nA: Infolge seiner Arbeit wurde er befoerdert.\nB: Harte Arbeit zahlt sich aus.",exampleSrc:"A: As a result of good preparation, he passed.\nB: As a result of the bad weather, she stayed home.\nA: As a result of his work, he was promoted.\nB: Hard work pays off.",funFact:"In + Folge (consequence). As a result of, owing to. A formal causal preposition. Takes Genitiv. 'Infolgedessen' (consequently) is the adverb form. Very formal register."},
{type:"teach",trg:"aufgrund der Tatsache dass",src:"due to the fact that",pos:"conj",gender:null,note:"Aufgrund (on the basis of) + der Tatsache (the fact) + dass.\nVery formal, academic register. Heavy but precise.",example:"A: Aufgrund der Tatsache, dass er viel geuebt hat, bestand er.\nB: Das klingt sehr formell.\nA: Ja, das ist akademisches Deutsch.\nB: Aufgrund der Tatsache, dass ich uebe, werde ich besser.",exampleSrc:"A: Due to the fact that he practiced a lot, he passed.\nB: That sounds very formal.\nA: Yes, that is academic German.\nB: Due to the fact that I practice, I get better.",funFact:"Aufgrund (on the basis of) + der Tatsache (the fact) + dass. Very formal, almost bureaucratic. Academic register. Heavy but precise. Shows B2-level writing command."},
{type:"teach",trg:"mit dem Ziel",src:"with the aim of",pos:"prep",gender:null,note:"Mit (with) + dem Ziel (the goal). Purpose expression.\nMore formal than 'um...zu.' Used with zu + Infinitiv.",example:"A: Er lernte täglich, mit dem Ziel, die Prüfung zu bestehen.\nB: Mit dem Ziel, C1 zu erreichen, lese ich Buecher.\nA: Mit welchem Ziel studierst du?\nB: Mit dem Ziel, in Deutschland zu arbeiten.",exampleSrc:"A: He studied daily, with the aim of passing the exam.\nB: With the aim of reaching C1, I read books.\nA: With what goal are you studying?\nB: With the aim of working in Germany.",funFact:"Mit (with) + dem Ziel (the goal). With the aim of. Purpose expression. More formal than 'um...zu.' 'Mit dem Ziel, die Prüfung zu bestehen, lernte er täglich.'"},
{type:"teach",trg:"zum Zweck",src:"for the purpose of",pos:"prep",gender:null,note:"Zum (for the) + Zweck (purpose). Very formal, almost\nbureaucratic. 'Zu welchem Zweck?' (For what purpose?)",example:"A: Zum Zweck der Prüfungsvorbereitung lese ich Texte.\nB: Zu welchem Zweck brauchst du das Wörterbuch?\nA: Zum Zweck des Nachschlagens.\nB: Sehr formell.",exampleSrc:"A: For the purpose of exam preparation, I read texts.\nB: For what purpose do you need the dictionary?\nA: For the purpose of looking things up.\nB: Very formal.",funFact:"Zum (for the) + Zweck (purpose). For the purpose of. Very formal, almost bureaucratic. 'Zu welchem Zweck?' (For what purpose?) is a formal question. Administrative register."},
{type:"mc",q:"'Infolge der guten Vorbereitung bestand er.' Was bedeutet 'infolge'?",opts:["Trotz der guten Vorbereitung","Als Ergebnis der guten Vorbereitung","Ohne die gute Vorbereitung","Anstatt der guten Vorbereitung"],ans:"Als Ergebnis der guten Vorbereitung",hint:"In + Folge (consequence). A formal causal preposition with Genitiv. It introduces the cause that led to the result."},
{type:"teach",trg:"um...willen",src:"for the sake of",pos:"prep",gender:null,note:"Um + noun (Genitiv) + willen (sake). Very formal. Genitiv\nrequired. 'Um Gottes willen!' (For God's sake!) is most common.",example:"A: Um der Klarheit willen erkläre ich das nochmal.\nB: Um Gottes willen, das ist schwer!\nA: Um der Wahrheit willen: die Prüfung war fair.\nB: Ja, um der Ehrlichkeit willen stimme ich zu.",exampleSrc:"A: For the sake of clarity, I will explain that again.\nB: For God's sake, that is hard!\nA: For the sake of truth: the exam was fair.\nB: Yes, for the sake of honesty, I agree.",funFact:"Um + noun (Genitiv) + willen (sake). For the sake of. Very formal. 'Um Gottes willen!' (For God's sake!) is the most common usage. Genitiv is required between um and willen."},
{type:"teach",trg:"was für ein",src:"what kind of",pos:"pron",gender:null,note:"Was (what) + für (for) + ein (a). An interrogative pronoun\nphrase. 'Ein' declines: was für einen, was für einer.",example:"A: Was für ein Text ist das?\nB: Ein argumentativer Text.\nA: Was für eine Aufgabe kommt als Nächstes?\nB: Eine Zuordnungsaufgabe.",exampleSrc:"A: What kind of text is that?\nB: An argumentative text.\nA: What kind of task comes next?\nB: A matching task.",funFact:"Was (what) + für (for) + ein (a). What kind of. An interrogative pronoun phrase. 'Was für ein Text ist das?' 'Ein' declines: was für einen, was für einer, was für einem."},
{type:"teach",trg:"ein jeder",src:"each and every one",pos:"pron",gender:null,note:"Ein + jeder (every). More emphatic and literary than 'jeder.'\nStresses the individual within the whole. Slightly poetic.",example:"A: Ein jeder hat seine Stärken.\nB: Und ein jeder hat Schwaechen.\nA: Ein jeder muss seinen Weg finden.\nB: Das stimmt.",exampleSrc:"A: Each and every one has their strengths.\nB: And each and every one has weaknesses.\nA: Each and every one must find their way.\nB: That is true.",funFact:"Ein + jeder (every). Each and every one. More emphatic than just 'jeder.' Literary quality. 'Ein jeder' stresses the individual within the whole. Slightly poetic register."},
{type:"teach",trg:"abgesehen davon",src:"apart from that, besides",pos:"adv",gender:null,note:"Abgesehen (seen away from) + davon (from that). A transition\nphrase that signals: setting that aside, here is another point.",example:"A: Die Prüfung war lang.\nB: Abgesehen davon war sie fair.\nA: Abgesehen davon, dass ich muede war, lief es gut.\nB: Abgesehen von der Laenge war alles in Ordnung.",exampleSrc:"A: The exam was long.\nB: Apart from that, it was fair.\nA: Apart from the fact that I was tired, it went well.\nB: Apart from the length, everything was fine.",funFact:"Abgesehen (seen away from) + davon (from that). Apart from that, besides. A transition phrase. Signals: setting that aside, here is another point. Very useful in B2 writing."},
{type:"fb",s:"{1} davon war die Pr\u00fcfung insgesamt fair.",a:["Abgesehen"],opts:["Aufgrund","Infolge","Abgesehen","Anstatt"],hint:"A transition phrase meaning 'apart from that.' It sets aside one point to make another. Paired with 'davon.'",sSrc:"Apart from that, the exam was overall fair."}
]},
{id:"deu_r35l7b",title:"Generalprobe (Teil 2)",icon:"\uD83C\uDFAF",xp:15,board:true,steps:[
{type:"intro",title:"Generalprobe (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"dessen ungeachtet",src:"notwithstanding that, despite that",pos:"adv",gender:null,note:"Dessen (of that) + ungeachtet (unregarded). Very formal.\nLegal and academic register. The formal version of 'trotzdem.'",example:"A: Die Prüfung war schwer.\nB: Dessen ungeachtet blieb er ruhig.\nA: Der Text war lang. Dessen ungeachtet las er alles.\nB: Sehr diszipliniert.",exampleSrc:"A: The exam was hard.\nB: Notwithstanding that, he remained calm.\nA: The text was long. Notwithstanding that, he read everything.\nB: Very disciplined.",funFact:"Dessen (of that) + ungeachtet (unregarded). Notwithstanding that, despite that. Very formal, legal and academic register. The formal version of 'trotzdem.' Shows elevated writing command."},
{type:"teach",trg:"im Uebrigen",src:"furthermore, incidentally",pos:"adv",gender:null,note:"Im (in the) + Uebrigen (remaining). A formal discourse marker.\nSignals an additional point. Elevates your writing register.",example:"A: Die Prüfung war fair.\nB: Im Uebrigen war die Organisation gut.\nA: Im Uebrigen möchte ich noch erwähnen...\nB: Im Uebrigen stimme ich zu.",exampleSrc:"A: The exam was fair.\nB: Furthermore, the organization was good.\nA: Furthermore, I would like to mention...\nB: Furthermore, I agree.",funFact:"Im (in the) + Uebrigen (remaining). Furthermore, incidentally. A formal discourse marker. Signals an additional point. 'Im Uebrigen möchte ich noch erwähnen...' Elevates register."},
{type:"teach",trg:"in erster Linie",src:"first and foremost, primarily",pos:"adv",gender:null,note:"In + erster (first) + Linie (line). What matters MOST.\n'In erster Linie geht es um Kommunikation.'",example:"A: Worauf kommt es in erster Linie an?\nB: In erster Linie auf den Inhalt.\nA: Und in zweiter Linie?\nB: Auf den Satzbau und den Ausdruck.",exampleSrc:"A: What matters first and foremost?\nB: First and foremost, the content.\nA: And secondly?\nB: Sentence structure and expression.",funFact:"In + erster (first) + Linie (line). First and foremost, primarily. The number one priority. What matters MOST. 'In erster Linie geht es um Kommunikation.' Clear hierarchy."},
{type:"teach",trg:"jedenfalls",src:"in any case, at any rate",pos:"adv",gender:null,note:"Jeden (every) + Falls (case). Regardless of what was said\nbefore, THIS is true. A transition word of certainty.",example:"A: War die Prüfung schwer?\nB: Jedenfalls habe ich mein Bestes gegeben.\nA: Jedenfalls ist es jetzt vorbei.\nB: Ja, jedenfalls können wir uns entspannen.",exampleSrc:"A: Was the exam hard?\nB: In any case, I did my best.\nA: In any case, it is over now.\nB: Yes, in any case, we can relax.",funFact:"Jeden (every) + Falls (case). In any case, at any rate. A transition word. Regardless of what was said before, THIS is true. 'Jedenfalls habe ich mein Bestes gegeben.'"},
{type:"mc",q:"Was ist der Unterschied zwischen 'indem' und 'ohne dass'?",opts:["Indem = weil. Ohne dass = obwohl und trotzdem.","Sie bedeuten genau dasselbe in anderen Worten.","Indem = wenn eine Bedingung gilt. Ohne dass = falls nicht erf\u00fcllt.","Indem = indem man X tut. Ohne dass = ohne X zu tun."],ans:"Indem = indem man X tut. Ohne dass = ohne X zu tun.",hint:"One describes the method applied. The other describes the method NOT applied."},
{type:"fb",s:"{1} der guten Vorbereitung bestand sie die Prüfung.",a:["Infolge"],opts:["Infolge","Indem","Ohne","Anstatt"],hint:"A formal causal preposition with Genitiv. It introduces the cause as a consequence. More elevated in register than 'wegen', pointing specifically to a resulting outcome.",sSrc:"As a result of good preparation, she passed the exam."},
{type:"teach",trg:"erwähnen",src:"to mention",pos:"verb",gender:null,note:"Formal register. More casual: sagen (to say) or ansprechen (to bring up).",example:"Ich möchte noch erwähnen, dass die Frist morgen endet.",exampleSrc:"I would also like to mention that the deadline ends tomorrow.",funFact:"The prefix er- often signals completion or achievement: wähnen (to assume) becomes erwähnen (to bring up explicitly)."},
{type:"drag_fill",s:"{1} möchte ich {2}, dass die Prüfung {3} fair war.",blanks:{"1":"Im Uebrigen","2":"erwähnen","3":"jedenfalls"},pool:["Im Uebrigen","erwähnen","jedenfalls","Abgesehen davon","sagen","trotzdem"],hint:"Three formal register markers: a discourse connector meaning 'furthermore', a verb meaning 'to mention/note', and an adverb meaning 'in any case/at any rate'. All formal written German.",sSrc:"Furthermore, I would like to mention that the exam was in any case fair."},
{type:"mc",q:"Welcher Satz demonstriert fortgeschrittenes Niveau mit Modalsatz + Indefinitpronomen + Modalpartikel + formellem Konnektor?",opts:["Alle Übungen sind nützlich, und mit der Zeit wird man definitiv viel sicherer und besser.","Indem man sämtliche Übungen macht, wird man halt besser. Im Uebrigen ist Vorbereitung alles.","Weil man regelmäßig und sorgfältig übt, wird man halt trotzdem irgendwann mühelos besser.","Man macht Prüfungsübungen regelmäßig und das ist halt sehr gut so für den eigenen Lernprozess."],ans:"Indem man sämtliche Übungen macht, wird man halt besser. Im Uebrigen ist Vorbereitung alles.",hint:"Four advanced features packed into two clauses: a HOW-clause, an emphatic word for totality, a particle of acceptance, and a formal linking adverb."},
{type:"match",pairs:[{trg:"dessen ungeachtet",src:"notwithstanding"},{trg:"in erster Linie",src:"first and foremost"},{trg:"im Uebrigen",src:"furthermore"},{trg:"abgesehen davon",src:"apart from that"},{trg:"jedenfalls",src:"in any case"}]},
{type:"fb",s:"Er lernte täglich, {1} dem Ziel, die Prüfung zu bestehen.",a:["mit"],opts:["zu","fuer","mit","ohne"],hint:"WITH the aim of passing the exam. A formal expression of purpose.",sSrc:"He studied daily, with the aim of passing the exam."},
{type:"drag_fill",s:"{1} dass er {2} Aufgaben bearbeitet hat, bestand er die Prüfung, {3} dass er nervoes war.",blanks:{"1":"Dadurch","2":"sämtliche","3":"ohne"},pool:["Dadurch","sämtliche","ohne","Indem","jegliche","anstatt"],hint:"Three constructs: a connector introducing a means or cause ('through the fact that'), an emphatic indefinite for totality, and a manner clause indicating what was absent. Three distinct layers in one sentence.",sSrc:"Through the fact that he completed all tasks, he passed the exam without being nervous."}]},
{id:"deu_r35l8",title:"Bestanden",icon:"\uD83C\uDF93",xp:15,board:true,steps:[
{type:"intro",title:"Bestanden",desc:"The exam result is in. Verumius opens the email. Two years of work in one click. Learn formal opinion markers and reflect on the B2 journey.",goals:["Find out the exam result","Master formal opinion markers (meines Erachtens, nichtsdestotrotz)","Reflect on Verumius's B2 journey with quiet pride"]},
{type:"teach",trg:"meines Erachtens",src:"in my opinion (formal)",pos:"adv",gender:null,note:"Meines (my, Genitiv) + Erachtens (considering). Very formal.\nAbbreviated 'm.E.' in academic writing.",example:"A: Meines Erachtens ist Vorbereitung entscheidend.\nB: Meines Erachtens auch.\nA: Wie formell klingt das?\nB: Sehr formell. Perfekt für B2-Aufsaetze.",exampleSrc:"A: In my opinion, preparation is crucial.\nB: In my opinion too.\nA: How formal does that sound?\nB: Very formal. Perfect for B2 essays.",funFact:"Meines (my, Genitiv) + Erachtens (considering). In my opinion/view. Very formal. Abbreviated 'm.E.' in academic writing. The most formal way to state an opinion in German."},
{type:"teach",trg:"nichtsdestotrotz",src:"nevertheless, nonetheless",pos:"adv",gender:null,note:"Nichts (nothing) + desto (the more) + trotz (despite).\nA famously long German word for a simple idea.",example:"A: Die Prüfung war schwer.\nB: Nichtsdestotrotz habe ich bestanden.\nA: Das Wetter war schlecht.\nB: Nichtsdestotrotz sind wir gewandert.",exampleSrc:"A: The exam was hard.\nB: Nevertheless, I passed.\nA: The weather was bad.\nB: Nevertheless, we went hiking.",funFact:"Nichts (nothing) + desto (the more) + trotz (despite). Nevertheless, nonetheless. A famously long German word for a simple idea. Five syllables where English uses three."},
{type:"teach",trg:"überdies",src:"moreover, furthermore",pos:"adv",gender:null,note:"Über (over/beyond) + dies (this). A formal discourse marker.\nMore elevated than 'ausserdem.' Academic register.",example:"A: Die Prüfung war fair.\nB: Überdies war die Organisation gut.\nA: Überdies möchte ich betonen...\nB: Überdies stimme ich zu.",exampleSrc:"A: The exam was fair.\nB: Moreover, the organization was good.\nA: Moreover, I would like to emphasize...\nB: Moreover, I agree.",funFact:"Über (over/beyond) + dies (this). Moreover, furthermore. A formal discourse marker. More elevated than 'ausserdem.' Shows command of academic register."},
{type:"teach",trg:"unter anderem",src:"among other things",pos:"adv",gender:null,note:"Unter (among) + anderem (other things). Abbreviated 'u.a.'\nin academic texts. Lists items without being exhaustive.",example:"A: Was wurde getestet?\nB: Unter anderem Leseverstehen und Hoerverstehen.\nA: Und was noch?\nB: Unter anderem auch Schreiben und Sprechen.",exampleSrc:"A: What was tested?\nB: Among other things, reading and listening comprehension.\nA: And what else?\nB: Among other things, also writing and speaking.",funFact:"Unter (among) + anderem (other things). Among other things. Abbreviated 'u.a.' in academic texts. Lists items without being exhaustive. 'Unter anderem wurde Leseverstehen getestet.'"},
{type:"mc",q:"'Nichtsdestotrotz habe ich bestanden.' Was dr\u00fcckt 'nichtsdestotrotz' aus?",opts:["Zustimmung: Ich stimme zu und habe bestanden","Ursache: Deswegen habe ich bestanden","Unsicherheit: Vielleicht habe ich bestanden","Gegensatz: Trotz der Schwierigkeit habe ich bestanden"],ans:"Gegensatz: Trotz der Schwierigkeit habe ich bestanden",hint:"Five syllables for a simple idea: 'in spite of everything.' It pushes against the previous statement, not with it."},
{type:"teach",trg:"vornehmlich",src:"primarily, chiefly",pos:"adv",gender:null,note:"Vornehm (distinguished/primarily) + -lich. Very formal.\nImplying what takes the foremost, most distinguished position.",example:"A: Was wird vornehmlich getestet?\nB: Vornehmlich die Kommunikationsfaehigkeit.\nA: Und vornehmlich welche Grammatik?\nB: Vornehmlich komplexe Satzstrukturen.",exampleSrc:"A: What is primarily tested?\nB: Primarily the ability to communicate.\nA: And primarily which grammar?\nB: Primarily complex sentence structures.",funFact:"Vornehm (distinguished/primarily) + -lich. Primarily, chiefly. Very formal. From 'vornehm' (noble/distinguished), implying what takes the foremost position. Elevated register."},
{type:"teach",trg:"fehlerhaft",src:"faulty, erroneous",pos:"adj",gender:null,note:"Fehler (error) + -haft (having/marked by). The -haft suffix\nmeans 'having the quality of.' Full of errors.",example:"A: Dein Satz ist fehlerhaft.\nB: Wo ist der Fehler?\nA: Fehlerhafte Saetze verlieren Punkte.\nB: Ich korrigiere das sofort.",exampleSrc:"A: Your sentence is faulty.\nB: Where is the error?\nA: Faulty sentences lose points.\nB: I will correct that immediately.",funFact:"Fehler (error) + -haft (having/marked by). Faulty, erroneous. 'Ein fehlerhafter Satz verliert Punkte.' The -haft suffix means 'having the quality of.' Fehler + haft = full of errors."},
{type:"teach",trg:"grammatikalisch",src:"grammatical",pos:"adj",gender:null,note:"From Greek 'grammatikos.' The adjective form of 'Grammatik.'\n'Grammatikalisch korrekte Saetze' is what the exam demands.",example:"A: Ist der Satz grammatikalisch korrekt?\nB: Ja, grammatikalisch einwandfrei.\nA: Grammatikalische Fehler kosten Punkte.\nB: Deshalb prüfe ich jeden Satz.",exampleSrc:"A: Is the sentence grammatically correct?\nB: Yes, grammatically flawless.\nA: Grammatical errors cost points.\nB: That is why I check every sentence.",funFact:"'Grammatikalisch korrekte Saetze' is what every exam demands. Same root across European languages, from Greek 'grammatikos.' The adjective form of 'Grammatik' and what examiners are really testing."},
{type:"teach",trg:"korrekt",src:"correct",pos:"adj",gender:null,note:"From Latin 'correctus.' Same word in English. In German slang,\n'Er ist korrekt' also means 'He is a decent person.'",example:"A: Ist diese Antwort korrekt?\nB: Ja, voellig korrekt.\nA: Korrekte Grammatik ist wichtig.\nB: Und korrekter Inhalt auch.",exampleSrc:"A: Is this answer correct?\nB: Yes, completely correct.\nA: Correct grammar is important.\nB: And correct content too.",funFact:"Same word in English, from Latin 'correctus.' In German slang, 'Er ist korrekt' also means 'He is a decent person.' A double meaning the classroom version does not teach you."},
{type:"fb",s:"Ein {1} Satz verliert Punkte in der Pr\u00fcfung.",a:["fehlerhafter"],opts:["fehlerhafter","vollst\u00e4ndiger","korrekter","w\u00f6rtlicher"],hint:"Fehler (error) + -haft (having the quality of). An adjective meaning 'containing errors.' The opposite of correct.",sSrc:"A faulty sentence loses points in the exam."},
{type:"mc",q:"Die Prüfung ist anspruchsvoll. {blank} ist die Zeit sehr knapp.",opts:["Überdies","Deshalb","Trotzdem","Jedoch"],ans:"Überdies",hint:"An adverb meaning 'moreover' or 'furthermore.' It adds another point to the argument. Formal register."}
]},
{id:"deu_r35l8b",title:"Bestanden (Teil 2)",icon:"\uD83C\uDF93",xp:15,board:true,steps:[
{type:"intro",title:"Bestanden (continued)",desc:"Continue practicing the vocabulary from this topic.",goals:["Review and practice key words"]},
{type:"teach",trg:"richtig",src:"right, correct",pos:"adj",gender:null,note:"From 'richten' (to direct/judge). More everyday than 'korrekt.'\n'Richtig!' is what teachers say when you get it right.",example:"A: Ist das richtig?\nB: Ja, das ist richtig.\nA: Richtig oder falsch?\nB: Richtig!",exampleSrc:"A: Is that right?\nB: Yes, that is right.\nA: Right or wrong?\nB: Right!",funFact:"'Richtig!' is what every German teacher says when you get it right. More everyday than 'korrekt,' it comes from 'richten' (to direct/judge). The word you will hear most in any classroom."},
{type:"teach",trg:"lueckenhaft",src:"incomplete, full of gaps",pos:"adj",gender:null,note:"Luecke (gap) + -haft. The opposite of 'vollständig.'\nWhen your knowledge has holes that need filling.",example:"A: Meine Grammatik ist noch lueckenhaft.\nB: Welche Luecken hast du?\nA: Lueckenhafte Kenntnisse im Genitiv.\nB: Das kann man üben.",exampleSrc:"A: My grammar is still incomplete.\nB: What gaps do you have?\nA: Incomplete knowledge of the genitive.\nB: You can practice that.",funFact:"Luecke (gap) + -haft. Incomplete, full of gaps. The opposite of 'vollständig.' When your knowledge has holes. 'Lueckenhafte Kenntnisse' (knowledge with gaps). Honest self-assessment."},
{type:"teach",trg:"vollständig",src:"complete, entire",pos:"adj",gender:null,note:"Voll (full) + ständig (standing/constant). Nothing missing.\nEverything present. What every exam answer should be.",example:"A: Ist deine Antwort vollständig?\nB: Ja, ich habe alles geschrieben.\nA: Vollständige Antworten bekommen volle Punkte.\nB: Deshalb prüfe ich alles nochmal.",exampleSrc:"A: Is your answer complete?\nB: Yes, I wrote everything.\nA: Complete answers get full points.\nB: That is why I check everything again.",funFact:"Voll (full) + ständig (standing/constant). Complete, entire. The gold standard. Nothing missing. Everything present. What every exam answer should be. 'Eine vollständige Antwort.'"},
{type:"teach",trg:"wörtlich",src:"literal, word-for-word",pos:"adj",gender:null,note:"Wort (word) + -lich. The opposite of 'sinngemaeess' (in\nmeaning/paraphrased). 'Wörtlich übersetzen' is risky.",example:"A: Übersetze nicht wörtlich.\nB: Warum nicht?\nA: Wörtliche Übersetzungen klingen unnatürlich.\nB: Also sinngemaeess statt wörtlich.",exampleSrc:"A: Do not translate literally.\nB: Why not?\nA: Literal translations sound unnatural.\nB: So by meaning instead of literally.",funFact:"Wort (word) + -lich. Literal, word-for-word. 'Wörtlich übersetzen' (to translate literally). The opposite of 'sinngemaeess' (in meaning/paraphrased). 'Wörtlich genommen' (taken literally)."},
{type:"teach",trg:"die Eroerterung",src:"discursive essay, argumentation",pos:"noun",gender:"f",note:"From 'eroertern' (to discuss/deliberate). The classic German\nessay type: present both sides, then take a position.",example:"A: Was ist eine Eroerterung?\nB: Ein Aufsatz mit Pro- und Contra-Argumenten.\nA: Wie endet eine Eroerterung?\nB: Mit einem Fazit und einer eigenen Position.",exampleSrc:"A: What is a discursive essay?\nB: An essay with pro and contra arguments.\nA: How does a discursive essay end?\nB: With a conclusion and a personal position.",funFact:"The classic German essay type: present both sides, then take a position. The B2 Schreibaufgabe is essentially an Eroerterung. The verb 'eroertern' means to discuss and deliberate carefully."},
{type:"match",pairs:[{trg:"lueckenhaft",src:"incomplete, full of gaps"},{trg:"vollständig",src:"complete, entire"},{trg:"wörtlich",src:"literal, word-for-word"},{trg:"die Eroerterung",src:"discursive essay, argumentation"}]},
{type:"teach",trg:"gegenüberstellen",src:"to compare, to juxtapose",pos:"verb",gender:null,note:"Gegenüber (opposite) + stellen (to place). Separable.\nPlacing two things opposite each other for comparison.",example:"A: Stellen Sie die Argumente gegenüber.\nB: Pro: Digitalisierung foerdert Lernen. Contra: Ablenkungsgefahr.\nA: Gut gegenübergestellt.\nB: Danke, die Struktur hilft.",exampleSrc:"A: Juxtapose the arguments.\nB: Pro: digitalization promotes learning. Contra: danger of distraction.\nA: Well juxtaposed.\nB: Thank you, the structure helps.",funFact:"Gegenüber (opposite) + stellen (to place). To compare, to contrast, to juxtapose. Separable. Placing two things opposite each other for comparison. 'Argumente gegenüberstellen.'"},
{type:"teach",trg:"nachschlagen",src:"to look up (in a reference)",pos:"verb",gender:null,note:"Nach (after/looking up) + schlagen (to hit/strike). Separable.\nLiterally 'to strike after' a word. Flipping dictionary pages.",example:"A: Schlag das Wort nach.\nB: In welchem Wörterbuch?\nA: Im Online-Wörterbuch.\nB: Ich schlage es sofort nach.",exampleSrc:"A: Look up the word.\nB: In which dictionary?\nA: In the online dictionary.\nB: I will look it up right away.",funFact:"Nach (after/looking up) + schlagen (to hit/strike). To look up (in a reference). Separable. Literally 'to strike after' a word. The physical act of flipping dictionary pages. Digital age, same verb."},
{type:"teach",trg:"das Bewertungskriterium",src:"assessment criterion",pos:"noun",gender:"n",note:"Bewertung (assessment) + Kriterium (criterion). The specific\nstandard by which exam performance is measured.",example:"A: Welche Bewertungskriterien gibt es?\nB: Inhalt, Struktur, Grammatik, Wortschatz.\nA: Welches Bewertungskriterium ist am wichtigsten?\nB: Alle vier zaehlen gleich.",exampleSrc:"A: What assessment criteria are there?\nB: Content, structure, grammar, vocabulary.\nA: Which assessment criterion is most important?\nB: All four count equally.",funFact:"Bewertung (assessment) + Kriterium (criterion). The specific standard by which exam performance is measured. Four Bewertungskriterien at B2: content, structure, grammar, vocabulary range."},
{type:"mc",q:"Was ist die formellste Art, eine Meinung auszudrücken?",opts:["Ich finde die Prüfung ganz fair und gut gemacht.","Meines Erachtens ist die Prüfung fair.","Die Prüfung ist halt fair und das ist halt so.","Für mich persönlich ist die Prüfung fair gestaltet."],ans:"Meines Erachtens ist die Prüfung fair.",hint:"The most formal opinion marker uses a fixed Genitiv expression from academic writing. Which option sounds most elevated?"},
{type:"fb",s:"Die Prüfung war schwer. {1} habe ich bestanden.",a:["Nichtsdestotrotz"],opts:["Nichtsdestotrotz","Deswegen","Indem","Halt"],hint:"The famously long German connective adverb meaning 'in spite of everything'. The opposite of 'deswegen'. It pushes against the previous statement.",sSrc:"The exam was hard. Nevertheless, I passed."},
{type:"drag_fill",s:"{1} war die Prüfung anspruchsvoll. {2} konnte ich sie bestehen, {3} ich systematisch gearbeitet habe.",blanks:{"1":"Meines Erachtens","2":"Nichtsdestotrotz","3":"indem"},pool:["Meines Erachtens","Nichtsdestotrotz","indem","Unter anderem","Trotzdem","weil"],hint:"Three formal register markers: a Genitiv opinion phrase, a concessive connector, and a manner clause opener. Each gap introduces a distinct rhetorical function.",sSrc:"In my opinion, the exam was challenging. Nevertheless, I was able to pass it by working systematically."},
{type:"match",pairs:[{trg:"meines Erachtens",src:"in my opinion (formal)"},{trg:"nichtsdestotrotz",src:"nevertheless"},{trg:"überdies",src:"moreover"},{trg:"vollständig",src:"complete"},{trg:"Eroerterung",src:"discursive essay"}]},
{type:"mc",q:"Verumius kam mit null Deutsch nach Berlin und hat die Goethe-Prüfung in zwei Jahren bestanden. Welche Modalpartikel passt am besten zu seinem Gefühl?",opts:["schon (einraeumend: Ja, es war schwer, aber er hat es geschafft.)","doch (Widerspruch: Das stimmt doch nicht wirklich so, wie du denkst)","halt (Resignation: Das ist halt leider nun einmal wirklich so gewesen)","wohl (Unsicherheit: Er ist wohl gerade krank oder vielleicht abwesend)"],ans:"schon (einraeumend: Ja, es war schwer, aber er hat es geschafft.)",hint:"The particle of concession followed by quiet triumph. It acknowledges difficulty while affirming success."},
{type:"mc",q:"Was bedeutet 'richtig'?",opts:["nevertheless, nonetheless","right, correct","in my opinion (formal)","to look up (in a reference)"],ans:"right, correct",hint:"One of the most basic German words. Also means 'really/truly' as an intensifier."},
{type:"fb",s:"Meine Grammatik ist noch {1}.",a:["lueckenhaft"],opts:["gegenüberstellen","vornehmlich","unter anderem","lueckenhaft"],hint:"Lücke (gap) + -haft (having the quality of). Full of gaps, incomplete.",sSrc:"My grammar is still incomplete."},
{type:"mc",q:"Was bedeutet 'gegenüberstellen'?",opts:["to compare, to juxtapose","primarily, chiefly","complete, entire","grammatical"],ans:"to compare, to juxtapose",hint:"gegenüber (opposite/across from) + stellen (to place). To place things side by side for comparison."},
{type:"fb",s:"Wie sagt man 'to look up (in a reference)' auf Deutsch? {1}",a:["nachschlagen"],opts:["nachschlagen","lueckenhaft","grammatikalisch","wörtlich"],hint:"nach- (after/following) + schlagen (to hit/open). To flip open a dictionary or reference book.",sSrc:"How do you say 'to look up (in a reference)' in German?"},
{type:"mc",q:"Was bedeutet 'das Bewertungskriterium'?",opts:["faulty, erroneous","in my opinion (formal)","to look up (in a reference)","assessment criterion"],ans:"assessment criterion",hint:"Bewertung (evaluation) + Kriterium (from Greek: krinein, to judge). The standard by which exams are graded."}
]}
]};

export default UNIT_35;
